def _augment_source_health_with_catalyst(source_health: dict | None) -> None:
    """把三个 event_calendar 的健康状况合并进 source_health.sources。

    每个 collector 写出的 JSON 含 coverage{hit, miss, errored}，
    hit/总 < 90% 或 errored > 5 时标 degraded，进 sources 字典让降级面板展示。

    inline 修改 source_health 字典（如果传入 None 则不动）。
    """
    if not isinstance(source_health, dict):
        return
    from datetime import date, datetime as _dt
    sources = source_health.setdefault("sources", {})
    today = date.today()
    DEGRADE_HIT_RATIO = 0.9
    DEGRADE_ERR_COUNT = 5
    STALE_DAYS = 2
    WEEKLY_STALE_DAYS = 7
    for rel, label, market_label in [
        ("data/event_calendar.json",         "event_calendar_cn",      "A 股事件日历"),
        ("data/event_calendar_hk.json",      "event_calendar_hk",      "港股事件日历"),
        ("data/event_calendar_us.json",      "event_calendar_us",      "美股事件日历"),
        ("data/event_calendar_hk_hkex.json", "event_calendar_hk_hkex", "港股 HKEX 披露易"),
        ("data/event_calendar_us_sec.json",  "event_calendar_us_sec",  "美股 SEC EDGAR"),
        ("data/event_calendar_us_form4.json","event_calendar_us_form4","美股 Form 4 内部人"),
    ]:
        path = os.path.join(_REPO, rel)
        if not os.path.exists(path):
            sources[label] = {
                "status": "down",
                "reason": "file_missing",
                "impact": f"{market_label} 文件缺失，推荐侧 📰 一句话解释会消失",
                "affected_fields": ["catalyst", "📰 推荐依据 前缀"],
                "unaffected_fields": ["主推荐排名", "评分"],
                "operator_action": f"重跑 `python3 -m stock_research.jobs.{label}_daily`",
                "last_event": {"ts": "", "detail": f"{rel} 不存在"},
            }
            continue
        try:
            with open(path, encoding="utf-8") as f:
                data = json.load(f)
        except Exception as e:
            sources[label] = {
                "status": "down",
                "reason": "invalid_json",
                "impact": f"{market_label} JSON 解析失败",
                "operator_action": "检查文件内容；重跑 collector",
                "last_event": {"ts": "", "detail": str(e)[:200]},
            }
            continue
        gen_at = data.get("generated_at") or ""
        try:
            gen_dt = _dt.fromisoformat(gen_at) if gen_at else None
        except Exception:
            gen_dt = None
        age_days = (today - gen_dt.date()).days if gen_dt else None

        # A 股 event_calendar.json 跟港股/美股 schema 不同（没有 coverage 字段）
        # A 股看 n_events 是否合理
        if label == "event_calendar_cn":
            n_events = int(data.get("n_events") or 0)
            stale = age_days is not None and age_days > STALE_DAYS
            nested_health = data.get("source_health") or {}
            nested_sources = nested_health.get("sources") or {}
            source_failures = []
            seen_failures = set()
            for source_name, row in nested_sources.items():
                if not isinstance(row, dict):
                    continue
                row_status = str(row.get("status") or "").lower()
                if row_status not in {"error", "down", "failed", "degraded"}:
                    continue
                raw_error = str(row.get("error") or row.get("reason") or "").strip()
                if "stock_restricted_release_queue_em" in source_name:
                    source_label = "解禁"
                elif "stock_ggcg_em" in source_name:
                    source_label = "增减持"
                elif "stock_yjbb_em" in source_name:
                    source_label = "财报"
                else:
                    source_label = source_name.split("/")[-1]

                err_low = raw_error.lower()
                if "missing_required_columns" in err_low:
                    reason_text = "字段变更/缺列"
                elif "read timed out" in err_low or "timeout" in err_low or "timed out" in err_low:
                    reason_text = "东方财富接口超时"
                elif "akshare_not_installed" in err_low:
                    reason_text = "akshare 未安装"
                else:
                    reason_text = raw_error[:36] or row_status

                failure_key = (source_label, reason_text)
                if failure_key in seen_failures:
                    continue
                seen_failures.add(failure_key)
                source_failures.append(f"{source_label}{reason_text}")
            failure_detail = "；".join(source_failures[:4])
            if n_events < 1000:
                impact = (
                    f"{market_label} 0 条：事件源失败（{failure_detail}），不是市场无事件"
                    if failure_detail and n_events == 0
                    else f"{market_label} 仅 {n_events} 条事件 (期望 1000+)，A 股票 📰 覆盖会偏低"
                )
                sources[label] = {
                    "status": "degraded",
                    "reason": "source_failed" if failure_detail and n_events == 0 else "few_events",
                    "impact": impact,
                    "affected_fields": ["A 股 catalyst"],
                    "unaffected_fields": ["港股 / 美股 catalyst"],
                    "operator_action": "修复 A 股事件源（适配解禁字段 / 东财接口重试或备用源）后重跑 `python3 -m stock_research.jobs.event_calendar_daily`",
                    "last_event": {"ts": gen_at, "detail": f"n_events={n_events}, age={age_days}d, failures={failure_detail or 'none'}"},
                }
            elif stale:
                sources[label] = {
                    "status": "degraded",
                    "reason": "stale",
                    "impact": f"{market_label} 已 {age_days} 天未刷新",
                    "operator_action": "重跑 event_calendar_daily",
                    "last_event": {"ts": gen_at, "detail": f"age={age_days}d"},
                }
            continue

        # HK/US 用 coverage
        cov = data.get("coverage") or {}
        hit = int(cov.get("hit") or 0)
        miss = int(cov.get("miss") or 0)
        errored = int(cov.get("errored") or 0)
        total = hit + miss + errored
        ratio = (hit / total) if total > 0 else 0.0
        stale_days = WEEKLY_STALE_DAYS if label == "event_calendar_us_form4" else STALE_DAYS
        stale = age_days is not None and age_days > stale_days
        problems = []
        if ratio < DEGRADE_HIT_RATIO and total > 0:
            problems.append(f"命中率 {ratio:.0%} (期望 ≥{DEGRADE_HIT_RATIO:.0%})")
        if errored > DEGRADE_ERR_COUNT:
            problems.append(f"错误 {errored} 只 (期望 ≤{DEGRADE_ERR_COUNT})")
        if stale:
            problems.append(f"已 {age_days} 天未刷新")
        if problems:
            sources[label] = {
                "status": "degraded",
                "reason": "low_coverage" if (ratio < DEGRADE_HIT_RATIO) else ("errors" if errored > DEGRADE_ERR_COUNT else "stale"),
                "impact": f"{market_label}: " + "；".join(problems),
                "affected_fields": [f"{market_label.split('事件')[0]}股 catalyst (📰 推荐依据)"],
                "unaffected_fields": ["其他市场 catalyst", "主推荐排名"],
                "operator_action": f"重跑 `python3 -m stock_research.jobs.{label}_daily`",
                "last_event": {"ts": gen_at, "detail": f"hit={hit}/miss={miss}/err={errored}, age={age_days}d"},
            }


def _augment_source_health_with_paid_sources(source_health: dict | None) -> None:
    """把付费源的运行状态并入 source_health，避免实际回退时页面看不见。"""
    if not isinstance(source_health, dict):
        return
    sources = source_health.setdefault("sources", {})
    try:
        from stock_research.core import tushare_client
        snapshot = tushare_client.source_health_snapshot(pipeline="dashboard")
        tushare_info = (snapshot.get("sources") or {}).get("tushare")
        if isinstance(tushare_info, dict):
            sources["tushare"] = tushare_info
    except Exception as e:
        sources["tushare"] = {
            "status": "degraded",
            "reason": "health_unchecked",
            "impact": "无法读取 Tushare 付费源健康状态；A 股数据源是否已回退不确定",
            "affected_fields": ["A 股行情", "A 股财报 / F-Score", "龙虎榜机构席位"],
            "unaffected_fields": ["美股", "港股", "主推荐公式"],
            "operator_action": "检查 tushare 依赖与 TUSHARE_TOKEN，然后重跑 dashboard",
            "last_event": {"ts": "", "detail": str(e)[:200]},
        }


# 把后端写进 JSON 的英文 reason / 供应商名翻译成大白话，
# 让面板上一眼能看懂"今天是哪家挂了 + 为啥挂"。
