def _stale_acceptance_strip_html(acceptance: dict) -> str:
    """B 红条 strip 版本：作为「系统体检 + 防御」合并卡顶部子区域（不再独立成卡）。

    2026-05-25 事故复盘：手工 retry 某一步后忘了重跑 acceptance check,
    dashboard 显示满屏过时 FAIL 误报让用户以为系统挂了。这里加 30 分钟阈值,
    超过就在合并卡顶部显示红 strip + 修复命令。
    """
    acc_at = acceptance.get("generated_at")
    if not acc_at:
        return ""
    try:
        acc_dt = datetime.fromisoformat(str(acc_at).replace("Z", "").split("+")[0])
    except Exception:
        return ""
    latest_dir = os.path.join(_REPO, "data", "latest")
    if not os.path.isdir(latest_dir):
        return ""
    latest_dt = None
    for name in os.listdir(latest_dir):
        if not name.endswith(".json"):
            continue
        if name == "production_acceptance_check.json":
            continue
        try:
            mtime = datetime.fromtimestamp(os.path.getmtime(os.path.join(latest_dir, name)))
        except Exception:
            continue
        if latest_dt is None or mtime > latest_dt:
            latest_dt = mtime
    if latest_dt is None:
        return ""
    delta_min = (latest_dt - acc_dt).total_seconds() / 60
    if delta_min < 30:
        return ""
    return f"""
    <div class="rounded-lg border border-rose-300 bg-rose-50 px-3 py-2 text-xs text-rose-900 mb-3">
      <div class="font-semibold mb-0.5">❗ 生产验收快照已过时 {int(delta_min)} 分钟，下方 FAIL/WARN 可能是误报</div>
      <div class="text-rose-800">
        最新文件 {html_lib.escape(latest_dt.strftime('%m-%d %H:%M'))} · 快照 {html_lib.escape(acc_dt.strftime('%m-%d %H:%M'))}。retry 后跑：
        <code class="bg-white px-1.5 py-0.5 rounded font-mono">python3 scripts/tools/production_acceptance_check.py &amp;&amp; ./build_dashboard.sh</code>
      </div>
    </div>"""


def _weekly_self_review_panel_html() -> str:
    """周末复盘摘要（静态嵌入，读 weekly_self_review_latest.json）。"""
    wr = _runtime_load_json("data/latest/weekly_self_review_latest.json")
    if not wr or not wr.get("summary"):
        return ""
    s = wr.get("summary") or {}
    week_label = html_lib.escape(str(wr.get("week_label") or ""))
    missed = int(s.get("missed") or 0)
    disobeyed = int(s.get("disobeyed") or 0)
    aligned = int(s.get("aligned") or 0)
    lucky = int(s.get("lucky_disobey") or 0)
    rows = []
    for title, key in (("错过", "missed"), ("没听话", "disobeyed")):
        for r in (wr.get(key) or [])[:3]:
            sym = html_lib.escape(str(r.get("symbol") or ""))
            name = html_lib.escape(str(r.get("name") or "").strip())
            mkt = html_lib.escape(str(r.get("market_label") or r.get("market") or "").strip())
            head_parts: list[str] = []
            if name and name != "—":
                head_parts.append(f"<strong>{name}</strong>")
            head_parts.append(f"<span class='text-slate-500'>{sym}</span>")
            if mkt:
                head_parts.append(f"<span class='text-[10px] px-1 py-0.5 rounded bg-slate-100 text-slate-600 border border-slate-200'>{mkt}</span>")
            head = " ".join(head_parts)
            note = html_lib.escape(str(r.get("note") or "")[:40])
            trail = r.get("trailing_5d_pct")
            ret_event = r.get("return_5d_pct")
            ret_val = trail if trail is not None else ret_event
            if ret_val is not None:
                val = float(ret_val)
                tone = "text-rose-600" if val > 0 else ("text-emerald-700" if val < 0 else "text-slate-500")
                if trail is not None:
                    lookback_days = r.get("trailing_lookback_days") or 5
                    label = f"近{int(lookback_days)}交易日"
                else:
                    label = "5d"
                ret_html = f" · <span class='{tone} font-mono'>{label} {val:+.1f}%</span>"
            else:
                ret_html = ""
            rows.append(f"<li class='text-xs text-slate-700'>{head} · {note}{ret_html}</li>")
    sample = "".join(rows) if rows else "<li class='text-xs text-slate-500'>上周无典型错过/没听话样本（5-25 之前数据已清，下周一起会有内容）</li>"
    md_path = html_lib.escape(f"docs/letters/weekly_self_review_{wr.get('week_label', '')}.md")
    return f"""
  <div class="mb-6 bg-gradient-to-r from-violet-50 to-slate-50 rounded-xl border border-violet-200 p-4">
    <div class="flex items-start justify-between gap-3 flex-wrap">
      <div>
        <h3 class="text-sm font-bold text-violet-900">📋 上周复盘 · 动作 vs 信号</h3>
        <p class="text-[11px] text-slate-600 mt-0.5">{week_label} · advisory · 详见 <code class="text-[10px]">{md_path}</code></p>
      </div>
      <div class="flex gap-3 text-xs font-mono">
        <span class="px-2 py-1 rounded bg-white border border-slate-200">错过 <strong>{missed}</strong></span>
        <span class="px-2 py-1 rounded bg-white border border-amber-200 text-amber-900">没听话 <strong>{disobeyed}</strong></span>
        <span class="px-2 py-1 rounded bg-white border border-emerald-200 text-emerald-800">对齐 <strong>{aligned}</strong></span>
        <span class="px-2 py-1 rounded bg-white border border-slate-200 text-slate-500">逆势 {lucky}</span>
      </div>
    </div>
    <ul class="mt-3 grid grid-cols-1 md:grid-cols-2 gap-1 list-disc list-inside">{sample}</ul>
  </div>
"""


def _catalyst_action_label_py(catalyst: str, validation: dict) -> str:
    """Python 端复现 JS _catalystActionBadge — 返回带色的 HTML 片段。"""
    if not catalyst or not isinstance(validation, dict):
        return ""
    summary = validation.get("summary_by_type") or {}
    # 从 catalyst 字符串推断 event key
    key = None
    if "📢 业绩预告" in catalyst:
        key = "earnings_preview"
    elif "🤝 并购" in catalyst or "🤝 收购完成" in catalyst:
        key = "ma_takeover"
    elif "🛑 停牌" in catalyst:
        key = "trading_halt"
    elif "💰 回购" in catalyst:
        key = "buyback"
    elif "🎯 大股东主动持仓" in catalyst:
        key = "active_holder_change"
    elif "🟢 内部人净买入" in catalyst:
        key = "insider_net_buy"
    elif "🔴 内部人净卖出" in catalyst:
        key = "insider_net_sell"
    elif "👤 高管变动" in catalyst:
        key = "material_event::👤 高管变动"
    elif "⚠️ 裁员" in catalyst:
        key = "material_event::⚠️ 裁员/退出"
    elif "📣 重大披露" in catalyst:
        key = "material_event::📣 重大披露"
    elif "📜 重大协议" in catalyst:
        key = "material_event::📜 重大协议"
    elif "EPS 实际" in catalyst and "超预期" in catalyst:
        import re as _r
        m = _r.search(r"超预期\s*\+(\d+(?:\.\d+)?)%", catalyst)
        if m:
            surp = float(m.group(1))
            key = "earnings::✅ 超预期 >+10%" if surp >= 10 else "earnings::↗️ 超预期 0~+10%"
    elif "EPS 实际" in catalyst and "差预期" in catalyst:
        import re as _r
        m = _r.search(r"差预期\s*-?(\d+(?:\.\d+)?)%", catalyst)
        if m:
            dec = float(m.group(1))
            key = "earnings::❌ 差预期 <-10%" if dec >= 10 else "earnings::↘️ 差预期 -10%~0"
    elif "财报：净利润同比" in catalyst:
        key = "earnings"
    if not key:
        return ""
    stats = summary.get(key)
    if not stats or not stats.get("by_horizon", {}).get("T+5"):
        return ""
    h5 = stats["by_horizon"]["T+5"]
    n = int(stats.get("n") or 0)
    mean = h5.get("mean", 0)
    hit = h5.get("hit_pos", 0)
    mean_str = f"{'+' if mean >= 0 else ''}{mean:.1f}%"
    if n < 5:
        return f'<span class="inline-block px-2 py-0.5 rounded text-[11px] border border-slate-300 bg-slate-100 text-slate-600">⚪ 样本不足 · 仅 {n} 次</span>'
    explain = f'类似 {n} 次 · 5天平均 <b>{mean_str}</b> · <b>{int(hit)}%</b> 涨'
    # 五档阈值：-1% ~ +1% noise 区显示为 ⚪ 中性灰色避免跟"强买"视觉打架
    if mean >= 3 and hit >= 60:
        return f'<span class="inline-block px-2 py-0.5 rounded text-[11px] border-2 border-emerald-500 bg-emerald-100 text-emerald-900 font-bold">🚀 该跟 · {explain}</span>'
    if mean > 1:
        return f'<span class="inline-block px-2 py-0.5 rounded text-[11px] border-2 border-emerald-400 bg-emerald-50 text-emerald-800 font-bold">📈 可关注 · {explain}</span>'
    if mean >= -1:
        return f'<span class="inline-block px-2 py-0.5 rounded text-[11px] border border-slate-300 bg-slate-50 text-slate-600">⚪ 中性 · {explain}</span>'
    if mean < -2:
        return f'<span class="inline-block px-2 py-0.5 rounded text-[11px] border-2 border-rose-500 bg-rose-100 text-rose-900 font-bold">📉 回避 · {explain}</span>'
    return f'<span class="inline-block px-2 py-0.5 rounded text-[11px] border-2 border-rose-300 bg-rose-50 text-rose-700 font-bold">↘️ 谨慎 · {explain}</span>'


def _market_label_py(ticker: str) -> str:
    t = (ticker or "").upper()
    if t.endswith(".HK"): return "🇭🇰 港"
    if t.endswith(".SS"): return "🇨🇳 沪"
    if t.endswith(".SZ"): return "🇨🇳 深"
    if t.endswith(".BJ"): return "🇨🇳 京"
    return "🇺🇸 美"


def _today_catalyst_movement_html() -> str:
    """今日决策台首屏 · 「📰 今日推荐动向」卡：🆕 新进入 / 📈 跃升 / 📉 跌出。"""
    appearance = _runtime_load_json("data/latest/picks_appearance.json")
    validation = _runtime_load_json("data/latest/catalyst_validation.json")
    if not appearance:
        return ""
    total_runs = int(appearance.get("total_runs") or 0)
    if total_runs < 2:
        return f"""
  <div class="bg-violet-50 border border-violet-200 rounded-xl p-4 mb-6">
    <div class="font-bold text-violet-900 mb-1">📰 今日推荐动向</div>
    <p class="text-sm text-violet-800">
      系统刚切换打分公式（5/25 12:10），历史推荐数据库正在累积。明日 daily_refresh 跑完才能开始算
      🆕 新进入 / 📈 跃升 / 📉 跌出。
    </p>
  </div>"""

    tickers = appearance.get("tickers") or {}
    # 加载 candidate 元信息用于补 name (v2 实际推荐池) + catalyst index 拿催化句
    v2 = _runtime_v2_recommendations() or []
    cand_meta = {(c.get("ticker") or "").upper(): c for c in v2 if c.get("ticker")}
    catalyst_idx = _build_catalyst_index()  # ticker → "📰 ..."

    # 三类列表
    new_items = []
    rise_items = []
    for tk, info in tickers.items():
        c = cand_meta.get(tk.upper())
        if not c:
            continue
        cnt = int(info.get("count") or 0)
        if cnt == 1:
            new_items.append((tk, info, c))
        rank_up = info.get("rank_up") or 0
        score_up = info.get("score_up") or 0
        if rank_up >= 3 or (score_up and score_up >= 2):
            rise_items.append((tk, info, c))
    dropouts = appearance.get("dropouts") or []

    # 加载持仓 ticker set
    held: set = set()
    review = _runtime_load_json("data/latest/real_holding_review.json")
    for it in (review.get("items") or []):
        s = (it.get("symbol") or it.get("code") or "").upper()
        if s:
            held.add(s)

    # 渲染一只票的行
    def _risk_badges_html(flags) -> str:
        """把 recommendation_picks.risk_flags_json 显示成人能看懂的短风险提示。"""
        if not flags:
            return ""
        if not isinstance(flags, list):
            flags = [flags]
        code_labels = {
            "ACUTE_PRICE_PULLBACK": "急跌风险",
            "PRICE_ACTION_REVIEW_GATE": "价格红旗",
            "OVERHEATED_1Y": "过热风险",
        }
        severity_cls = {
            "high": "border-rose-300 bg-rose-50 text-rose-800",
            "medium": "border-orange-300 bg-orange-50 text-orange-800",
            "low": "border-amber-300 bg-amber-50 text-amber-800",
        }
        chips = []
        for flag in flags[:2]:
            if isinstance(flag, dict):
                code = str(flag.get("code") or "")
                severity = str(flag.get("severity") or "").lower()
                message = str(flag.get("message") or code or "风险提示")
            else:
                code = ""
                severity = ""
                message = str(flag or "")
            message = message.strip()
            if not message:
                continue
            label = code_labels.get(code, "风险提示")
            short_msg = message
            if "单日" in short_msg and "。" in short_msg:
                short_msg = short_msg.split("。", 1)[0]
            if len(short_msg) > 42:
                short_msg = short_msg[:42] + "..."
            cls = severity_cls.get(severity, "border-amber-300 bg-amber-50 text-amber-800")
            title = " · ".join(x for x in [code, severity, message] if x)
            chips.append(
                f'<span class="inline-flex items-center max-w-full px-2 py-0.5 rounded border text-[11px] font-semibold {cls}" title="{html_lib.escape(title, quote=True)}">'
                f'⚠️ {html_lib.escape(label)}：{html_lib.escape(short_msg)}</span>'
            )
        if not chips:
            return ""
        return f'<div class="mt-1 flex flex-wrap gap-1">{"".join(chips)}</div>'

    def _row_html(tk: str, name: str, catalyst: str, extra: str = "", risk_flags=None) -> str:
        """超紧凑 card：用于 3 列 grid。代码+名称一行；催化 truncate 一行（hover 看全）；extra 可选。"""
        market = _market_label_py(tk)
        action_inline = _catalyst_action_label_py(catalyst, validation) if catalyst else ""
        held_warn = "<span class='inline-block px-1 py-0 rounded text-[9px] font-bold bg-amber-200 text-amber-900 ml-1'>⚠️</span>" if tk.upper() in held else ""
        catalyst_disp = html_lib.escape(catalyst) if catalyst else '<span class="text-slate-300">—</span>'
        cat_title = html_lib.escape(catalyst) if catalyst else "无近期催化"
        risk_html = _risk_badges_html(risk_flags)
        return f"""
        <div class="bg-white rounded border border-slate-200 px-2 py-1 text-[11px] leading-tight" title="{cat_title}">
          <div class="flex items-baseline gap-1 mb-0.5 overflow-hidden">
            <span class="text-[8px] text-slate-400 font-mono shrink-0">{market}</span>
            <span class="font-mono font-bold text-slate-900 shrink-0">{html_lib.escape(tk)}</span>
            <span class="text-slate-700 truncate flex-1 min-w-0">{html_lib.escape(name or '')}</span>
            {held_warn}
          </div>
          <div class="text-[10.5px] text-slate-500 truncate">{catalyst_disp}</div>
          {('<div class="mt-0.5 scale-90 origin-left">' + action_inline + '</div>') if action_inline else ''}
          {risk_html}
          {extra}
        </div>"""

    # 🆕 新进入
    new_html = ""
    if new_items:
        new_items.sort(key=lambda x: (_market_label_py(x[0]), x[0]))
        rows = []
        for tk, info, c in new_items:
            name = c.get("name") or ""
            catalyst = catalyst_idx.get(tk.upper()) or ""
            rows.append(_row_html(tk, name, catalyst, risk_flags=c.get("risk_flags")))
        new_html = f"""
    <div class="mb-3">
      <div class="font-bold text-violet-900 text-[13px] mb-1.5">🆕 今日新进入推荐 <span class="text-slate-500 font-normal">({len(new_items)} 只)</span></div>
      <div class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-1.5">{''.join(rows)}</div>
    </div>"""

    # 📈 跃升
    rise_html = ""
    if rise_items:
        rise_items.sort(key=lambda x: -(x[1].get("rank_up") or 0))
        rows = []
        for tk, info, c in rise_items:
            name = c.get("name") or ""
            catalyst = catalyst_idx.get(tk.upper()) or ""
            rank_up = info.get("rank_up") or 0
            score_up = info.get("score_up") or 0
            extra_parts = []
            if rank_up >= 3:
                extra_parts.append(f"排名 {info.get('prev_rank')}→{info.get('cur_rank')} (+{rank_up})")
            if score_up and score_up >= 2:
                extra_parts.append(f"评分 +{score_up:.1f}")
            extra = f'<div class="text-[11px] text-amber-700 mt-0.5">📈 ' + " · ".join(extra_parts) + '</div>' if extra_parts else ""
            rows.append(_row_html(tk, name, catalyst, extra, risk_flags=c.get("risk_flags")))
        rise_html = f"""
    <div class="mb-3">
      <div class="font-bold text-amber-900 text-[13px] mb-1.5">📈 今日排名跃升 <span class="text-slate-500 font-normal">({len(rise_items)} 只)</span></div>
      <div class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-1.5">{''.join(rows)}</div>
    </div>"""

    # 📉 跌出
    drop_html = ""
    if dropouts:
        # 持仓置顶
        sorted_drops = sorted(dropouts, key=lambda d: (0 if (d.get("ticker") or "").upper() in held else 1, d.get("prev_rank") or 99))
        rows = []
        for d in sorted_drops:
            tk = d.get("ticker") or ""
            name = d.get("name") or ""
            prev_rank = d.get("prev_rank")
            prev_score = d.get("prev_score")
            extra = f'<div class="text-[11px] text-rose-700 mt-0.5">📉 上次第 {prev_rank} 名 · 综合 {prev_score}</div>' if prev_rank else ""
            rows.append(_row_html(tk, name, "", extra))
        held_in_drop = sum(1 for d in dropouts if (d.get("ticker") or "").upper() in held)
        warn = f' <span class="text-xs text-amber-700 font-bold">⚠️ 含 {held_in_drop} 只你持仓</span>' if held_in_drop else ""
        drop_html = f"""
    <div class="mb-2">
      <div class="font-bold text-rose-900 text-[13px] mb-1.5">📉 今日跌出推荐 <span class="text-slate-500 font-normal">({len(dropouts)} 只){warn}</span></div>
      <div class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-1.5">{''.join(rows)}</div>
    </div>"""

    if not (new_html or rise_html or drop_html):
        return """
  <div class="bg-slate-50 border border-slate-200 rounded-xl p-4 mb-6">
    <div class="font-bold text-slate-700 mb-1">📰 今日推荐动向</div>
    <p class="text-sm text-slate-600">今日推荐池跟昨日完全一致 · 没有新进入 / 跃升 / 跌出。</p>
  </div>"""

    return f"""
  <div class="bg-gradient-to-br from-amber-50 to-rose-50 border-2 border-amber-200 rounded-2xl p-5 mb-6 shadow-sm">
    <div class="flex items-center justify-between mb-4 flex-wrap gap-2">
      <div>
        <h3 class="font-bold text-slate-900 text-lg">📰 今日推荐动向</h3>
        <p class="text-xs text-slate-600 mt-1">
          昨日 → 今日 推荐池变化 · 每条带「为啥推」+「历史这类信号靠不靠谱」·
          <a href="#discovery" class="text-violet-700 hover:underline">完整 AI 推荐 →</a>
          <a href="#catalyst-validation" class="text-violet-700 hover:underline ml-2">催化信号验证 →</a>
        </p>
      </div>
    </div>
    {new_html}
    {rise_html}
    {drop_html}
  </div>"""


def today_decision_panel_html() -> str:
    clean_v2 = _is_clean_v2_db()
    quality = _runtime_load_json("data/latest/recommendation_quality_gate.json")
    acceptance = _runtime_load_json("data/latest/production_acceptance_check.json")
    evidence = _runtime_load_json("data/latest/recommendation_evidence.json")
    source_health = _runtime_load_json("data/latest/source_health.json")
    discovery = {} if clean_v2 else _runtime_load_json("data/discovery_candidates.json")
    v2_candidates = _runtime_v2_recommendations()
    if v2_candidates:
        v2_stats = _runtime_db_stats().get("v2") or {}
        discovery = {
            "generated_at": datetime.now().isoformat(timespec="seconds"),
            "source": "v2:recommendation_picks",
            "universe_scope": "system_tech_universe",
            "universe_size": v2_stats.get("system_universe") or len(v2_candidates),
            "candidates": v2_candidates,
        }
    db = _runtime_db_stats()

    quality_status = str(quality.get("status") or "UNKNOWN").upper()
    acceptance_status = str(acceptance.get("status") or "UNKNOWN").upper()
    evidence_grade = str(evidence.get("evidence_grade") or "—")
    v2_candidates = _runtime_v2_recommendations()
    discovery_candidates = v2_candidates or (discovery.get("candidates") or [])
    discovery_n = len(discovery_candidates)
    discovery_source = "v2 recommendation_picks" if v2_candidates else ("none" if clean_v2 else "legacy discovery_candidates.json")

    blocking = quality_status == "FAIL" or acceptance_status == "FAIL"
    if blocking:
        overall = "FAIL"
        overall_text = "今天推荐只能只读观察，先看系统状态里的失败项。"
    elif quality_status in {"PASS", "OK"} and acceptance_status in {"PASS", "OK"} and discovery_n:
        overall = "OK"
        overall_text = "今天链路可用，可以从 AI 推荐进入买前研究。"
    else:
        overall = "WARN"
        overall_text = "今天有数据，但部分产物或证据不足，建议先核对系统状态。"

    price_stats = db.get("prices") or {}
    v2 = db.get("v2") or {}
    coverage = v2.get("price_coverage") or {}
    latest_price_date = price_stats.get("latest_date") or "—"
    pool_total = int(v2.get("system_universe") or 0)
    pool_membership = int(v2.get("pool_membership") or 0)
    price_coverage_text = (
        f"行情覆盖 {coverage.get('priced', 0)}/{coverage.get('active_pool', 0)} "
        f"({coverage.get('pct', 0)}%) · 最新行情 {latest_price_date}"
    )
    market_line = (
        f"系统池 {pool_total} 只 · 池成员 {pool_membership} 只 · "
        f"{price_coverage_text}"
    )

    v2_counts = db.get("v2") or {}
    plan_artifact = _runtime_artifact("data/latest/plan_a_v5.json")
    trade_artifact = _runtime_artifact("data/latest/trade_delta.json")
    plan = _runtime_load_json("data/latest/plan_a_v5.json") or _runtime_pipeline_snapshot("plan_a_v5")
    trade_delta = _runtime_load_json("data/latest/trade_delta.json") or _runtime_pipeline_snapshot("trade_delta")
    plan_status = "OK" if int(v2_counts.get("portfolio_plans") or 0) > 0 or plan else plan_artifact["status"]
    trade_text = "存在" if trade_delta else trade_artifact["text"]
    plan_rows = plan.get("plan_v6") or plan.get("plan_v5") or plan.get("plan") or plan.get("portfolio") or []
    plan_metrics = plan.get("portfolio_metrics") or {}
    plan_detail = f"{int(v2_counts.get('portfolio_plans') or 0)} 只 v2 目标组合" if int(v2_counts.get("portfolio_plans") or 0) > 0 else (
        f"{len(plan_rows)} 只目标组合" if plan_rows else "暂无目标组合产物"
    )
    if plan_metrics.get("annual_sharpe") is not None:
        plan_detail += f" · Sharpe {plan_metrics.get('annual_sharpe')}"

    def fmt_num(value, digits=2):
        try:
            return f"{float(value):.{digits}f}"
        except Exception:
            return "—"

    def fmt_pct(value, digits=1):
        try:
            x = float(value) * 100.0 if abs(float(value)) <= 1 else float(value)
            return f"{x:+.{digits}f}%"
        except Exception:
            return "—"

    def fmt_weight(value):
        try:
            return f"{float(value) * 100:.1f}%"
        except Exception:
            return "—"

    def fmt_money_rmb(value):
        try:
            x = float(value)
        except Exception:
            return "—"
        if abs(x) >= 10000:
            return f"¥{x / 10000:.1f}万"
        return f"¥{x:,.0f}"

    def short_text(value, limit=54):
        s = str(value or "").strip()
        return s if len(s) <= limit else s[:limit] + "..."

    def coerce_flag(flag):
        if isinstance(flag, dict):
            return flag
        if isinstance(flag, str) and flag.strip().startswith("{"):
            try:
                import ast
                parsed = ast.literal_eval(flag)
                if isinstance(parsed, dict):
                    return parsed
            except Exception:
                return flag
        return flag

    def flag_message(flag) -> str:
        flag = coerce_flag(flag)
        if isinstance(flag, dict):
            return str(flag.get("message") or flag.get("code") or "风险提示")
        return str(flag or "")

    def flag_label(flag) -> str:
        flag = coerce_flag(flag)
        code = str(flag.get("code") or "") if isinstance(flag, dict) else ""
        return {
            "ACUTE_PRICE_PULLBACK": "急跌风险",
            "PRICE_ACTION_REVIEW_GATE": "价格红旗",
            "STRUCTURAL_DOWNTREND_REVIEW_GATE": "结构下跌",
            "OVERHEATED_1Y": "过热风险",
        }.get(code, "风险提示")

    def flag_severity(flag) -> str:
        flag = coerce_flag(flag)
        return str(flag.get("severity") or "").lower() if isinstance(flag, dict) else ""

    def risk_chip(flag, compact=False) -> str:
        msg = flag_message(flag)
        if not msg:
            return '<span class="text-slate-400">未命中结构化风险</span>'
        sev = flag_severity(flag)
        cls = "border-rose-200 bg-rose-50 text-rose-800" if sev == "high" else "border-orange-200 bg-orange-50 text-orange-800"
        label = flag_label(flag)
        limit = 34 if compact else 72
        return (
            f'<span class="inline-flex max-w-full px-2 py-0.5 rounded border text-[11px] font-semibold {cls}" '
            f'title="{html_lib.escape(msg, quote=True)}">⚠️ {html_lib.escape(label)}：{html_lib.escape(short_text(msg, limit))}</span>'
        )

    def factor_badge(label: str, value, tone: str = "slate") -> str:
        tone_cls = {
            "emerald": "bg-emerald-50 text-emerald-700 border-emerald-200",
            "amber": "bg-amber-50 text-amber-700 border-amber-200",
            "rose": "bg-rose-50 text-rose-700 border-rose-200",
            "slate": "bg-slate-50 text-slate-600 border-slate-200",
        }.get(tone, "bg-slate-50 text-slate-600 border-slate-200")
        return f'<span class="inline-flex px-1.5 py-0.5 rounded border text-[11px] font-semibold {tone_cls}">{html_lib.escape(label)} {fmt_num(value, 0)}</span>'

    def candidate_factor_summary(c: dict, b: dict) -> tuple[str, str]:
        factors = c.get("factor_scores") if isinstance(c, dict) else {}
        factors = factors if isinstance(factors, dict) else {}
        valuation = factors.get("valuation")
        momentum = factors.get("momentum")
        reversal = factors.get("reversal")
        quality = factors.get("data_quality") or factors.get("quality")
        total = b.get("composite_z") or c.get("composite_z")

        phrases = []
        if isinstance(valuation, (int, float)):
            phrases.append("估值分高" if valuation >= 80 else ("估值一般" if valuation >= 55 else "估值压力"))
        if isinstance(momentum, (int, float)):
            phrases.append("趋势强" if momentum >= 70 else ("趋势偏弱" if momentum < 45 else "趋势中性"))
        if isinstance(reversal, (int, float)):
            phrases.append("短线修复好" if reversal >= 70 else ("反转弱，别追" if reversal < 25 else "短线中性"))
        if isinstance(quality, (int, float)) and quality >= 90:
            phrases.append("数据质量足")
        if not phrases:
            phrases.append("AI 配仓候选，先做买前研究")
        headline = " · ".join(phrases[:3])

        badges = [f'<span class="inline-flex px-1.5 py-0.5 rounded border text-[11px] font-semibold bg-violet-50 text-violet-700 border-violet-200">总分 {fmt_num(total, 1)}</span>']
        if isinstance(valuation, (int, float)):
            badges.append(factor_badge("估值", valuation, "emerald" if valuation >= 80 else "slate"))
        if isinstance(momentum, (int, float)):
            badges.append(factor_badge("趋势", momentum, "emerald" if momentum >= 70 else ("amber" if momentum < 45 else "slate")))
        if isinstance(reversal, (int, float)):
            badges.append(factor_badge("反转", reversal, "emerald" if reversal >= 70 else ("rose" if reversal < 25 else "slate")))
        return headline, "".join(badges[:4])

    def policy_label(value: str, kind: str) -> str:
        labels = {
            "eligibility": {
                "buyable": "可进候选",
                "research_only": "只研究",
                "watch_only": "只观察",
                "excluded": "已剔除",
            },
            "action": {
                "focus_research": "重点研究",
                "wait_entry": "等买点",
                "watch_only": "只观察",
                "research_only": "只研究",
                "blocked": "红旗拦截",
                "exclude": "剔除",
            },
            "layer": {
                "ai_core": "AI核心",
                "ai_infrastructure": "AI基建",
                "tech_software": "科技软件",
                "internet_platform": "互联网平台",
                "power_datacenter": "电力/数据中心",
                "theme_watch": "主题观察",
                "excluded": "非科技成长",
            },
            "evidence": {
                "confirmed": "证据确认",
                "needs_review": "待复核",
                "candidate": "线索",
                "stale": "证据过期",
                "missing": "缺证据",
            },
        }
        return labels.get(kind, {}).get(str(value or ""), str(value or "—"))

    def policy_tone(value: str) -> str:
        v = str(value or "")
        if v in {"buyable", "focus_research", "confirmed", "ai_core", "ai_infrastructure", "power_datacenter"}:
            return "bg-emerald-50 text-emerald-700 border-emerald-200"
        if v in {"wait_entry", "needs_review", "candidate", "tech_software", "internet_platform"}:
            return "bg-amber-50 text-amber-700 border-amber-200"
        if v in {"blocked", "exclude", "excluded", "stale", "missing"}:
            return "bg-rose-50 text-rose-700 border-rose-200"
        return "bg-slate-50 text-slate-600 border-slate-200"

    def policy_badges(c: dict) -> str:
        items = [
            ("layer", c.get("primary_layer")),
            ("evidence", c.get("evidence_status")),
            ("eligibility", c.get("eligibility")),
        ]
        chips = []
        for kind, value in items:
            if not value:
                continue
            chips.append(
                f'<span class="inline-flex px-1.5 py-0.5 rounded border text-[11px] font-semibold {policy_tone(str(value))}">'
                f'{html_lib.escape(policy_label(str(value), kind))}</span>'
            )
        return "".join(chips)

    def candidate_action_line(c: dict, b: dict, flags: list) -> tuple[str, str, str]:
        factors = c.get("factor_scores") if isinstance(c, dict) else {}
        factors = factors if isinstance(factors, dict) else {}
        momentum = factors.get("momentum")
        reversal = factors.get("reversal")
        score = b.get("composite_z") or c.get("composite_z") or 0
        eligibility = str(c.get("eligibility") or "")
        action = str(c.get("action") or "")
        if eligibility == "excluded" or action == "exclude":
            return "剔除", "身份不属于科技成长主线，不进入买前研究。", "bg-rose-50 text-rose-800 border-rose-200"
        if action == "blocked":
            return "红旗拦截", "短期风险拦截，先等红旗解除。", "bg-rose-50 text-rose-800 border-rose-200"
        if action == "wait_entry":
            return "等买点", "逻辑仍可研究，但现在不是直接买点。", "bg-amber-50 text-amber-800 border-amber-200"
        if action == "research_only" or eligibility == "research_only":
            return "只研究", "证据或数据未满足可买候选，先补买前审查。", "bg-sky-50 text-sky-800 border-sky-200"
        if action == "watch_only" or eligibility == "watch_only":
            return "只观察", "主题相关但公司级证据不足，先不进真钱候选。", "bg-slate-50 text-slate-700 border-slate-200"
        if action == "focus_research":
            return "重点研究", "通过 P0 闸门，可进入买前研究，通过后再小批。", "bg-emerald-50 text-emerald-800 border-emerald-200"
        if flags:
            return "先复查", "有红旗，买前研究不过不动。", "bg-orange-50 text-orange-800 border-orange-200"
        if isinstance(reversal, (int, float)) and reversal < 25 and isinstance(momentum, (int, float)) and momentum >= 70:
            return "等回踩", "趋势强但短线反转弱，开盘追高不划算。", "bg-amber-50 text-amber-800 border-amber-200"
        if isinstance(momentum, (int, float)) and momentum < 45:
            return "先验证", "分数靠估值/质量，先确认不是便宜陷阱。", "bg-sky-50 text-sky-800 border-sky-200"
        if isinstance(score, (int, float)) and score >= 82:
            return "优先看", "可进入买前研究，通过后再小批。", "bg-emerald-50 text-emerald-800 border-emerald-200"
        return "候补看", "排在后面，先看前几只和持仓纪律。", "bg-slate-50 text-slate-700 border-slate-200"

    def attention_item(title: str, detail: str, href: str = "", tone: str = "amber") -> str:
        tone_cls = {
            "rose": "border-rose-200 bg-rose-50 text-rose-900",
            "amber": "border-amber-200 bg-amber-50 text-amber-900",
            "emerald": "border-emerald-200 bg-emerald-50 text-emerald-900",
            "slate": "border-slate-200 bg-slate-50 text-slate-800",
        }.get(tone, "border-amber-200 bg-amber-50 text-amber-900")
        link = f'<a href="{href}" class="text-xs font-semibold underline decoration-transparent hover:decoration-current">去处理</a>' if href else ""
        return f"""
          <div class="rounded-lg border px-3 py-2 {tone_cls}">
            <div class="flex items-start justify-between gap-3">
              <div>
                <div class="text-sm font-bold">{html_lib.escape(title)}</div>
                <div class="text-xs mt-0.5 opacity-85">{html_lib.escape(detail)}</div>
              </div>
              {link}
            </div>
          </div>
"""

    real_review = _runtime_load_json("data/latest/real_holding_review.json") or {}
    holding_items = real_review.get("items") or []

    holding_rows = []
    for h in holding_items:
        symbol = h.get("symbol") or h.get("code") or "?"
        action = h.get("action_label") or "观察"
        price = h.get("current_price")
        currency = h.get("current_currency") or ""
        pnl = h.get("pnl_pct")
        score = h.get("score")
        weight = h.get("current_weight")
        target = h.get("target_weight")
        discipline = h.get("discipline") or {}
        next_trigger = (discipline.get("next_triggers") or [None])[0] if isinstance(discipline, dict) else None
        if discipline and discipline.get("triggered"):
            discipline_line = f"{discipline.get('action_label') or '已触发'} · {discipline.get('suggested_size_text') or ''}"
        elif next_trigger:
            discipline_line = (
                f"下一线 {next_trigger.get('threshold_text') or '—'} · "
                f"{next_trigger.get('action_label') or '复查'} · {next_trigger.get('suggested_size_text') or ''}"
            )
        else:
            discipline_line = "未设置纪律线"
        risks = h.get("risk_flags") or []
        risk_html = risk_chip(risks[0], compact=True) if risks else '<span class="text-slate-400">未命中强风险</span>'
        action_cls = "bg-rose-50 text-rose-800 border-rose-200" if "减" in str(action) or "退" in str(action) else "bg-emerald-50 text-emerald-800 border-emerald-200"
        holding_rows.append(f"""
          <tr class="border-b border-slate-100 last:border-0 align-top">
            <td class="py-3 pr-3">
              <div class="font-mono font-bold text-slate-900">{html_lib.escape(str(symbol))}</div>
              <div class="text-[11px] text-slate-500">分 {fmt_num(score, 1)} · 仓位 {fmt_weight(weight)}{f' / 目标 {fmt_weight(target)}' if target is not None else ''}</div>
            </td>
            <td class="py-3 pr-3 whitespace-nowrap">
              <span class="inline-flex px-2 py-0.5 rounded border text-xs font-semibold {action_cls}">{html_lib.escape(str(action))}</span>
              <div class="text-[11px] text-slate-500 mt-1">{fmt_num(price, 2)} {html_lib.escape(str(currency))} · {fmt_pct(pnl, 2)}</div>
            </td>
            <td class="py-3 pr-3 text-xs text-slate-700">{html_lib.escape(short_text(discipline_line, 86))}</td>
            <td class="py-3 text-xs">{risk_html}</td>
          </tr>
""")
    if not holding_rows:
        holding_rows.append("""
          <tr><td colspan="4" class="py-6 text-center text-sm text-slate-500">暂无真实持仓体检；录入持仓后这里会显示纪律线和风险。</td></tr>
""")

    # 用户不想看 A 股科技/AI 池，决策台候选优先取美股。
    us_candidates = [
        c for c in discovery_candidates
        if str(c.get("market") or c.get("location") or "").upper() == "US"
    ]
    rec_by_ticker = {(c.get("ticker") or c.get("code") or "").upper(): c for c in us_candidates}
    plan_buy_rows = []
    for p in plan_rows:
        if not isinstance(p, dict):
            continue
        ticker = p.get("ticker") or p.get("symbol") or p.get("code")
        weight = p.get("capped_weight", p.get("target_weight", p.get("v6_weight")))
        try:
            active_weight = float(weight or 0)
        except Exception:
            active_weight = 0.0
        if ticker and active_weight > 0:
            plan_buy_rows.append({
                "ticker": ticker,
                "name": p.get("name") or ticker,
                "v6_weight": active_weight,
                "amount_rmb": p.get("amount_rmb") or p.get("amount"),
                "price_local": p.get("price_local") or p.get("entry_price"),
                "shares_estimate": p.get("shares_estimate"),
                "composite_z": p.get("composite_z") or p.get("score"),
            })
    buy_rows_source = plan_buy_rows or list((trade_delta or {}).get("buys") or [])
    if not buy_rows_source:
        buy_rows_source = [
            {
                "ticker": c.get("ticker") or c.get("code") or "?",
                "name": c.get("name") or "",
                "v6_weight": None,
                "amount_rmb": None,
                "price_local": c.get("entry_price"),
                "shares_estimate": None,
                "composite_z": c.get("composite_z"),
            }
            for c in us_candidates[:5]
        ]
    candidate_rows = []
    for idx, b in enumerate(buy_rows_source[:5], start=1):
        ticker = str(b.get("ticker") or "?").upper()
        c = rec_by_ticker.get(ticker) or {}
        flags = c.get("risk_flags") or []
        why_line, factor_badges = candidate_factor_summary(c, b)
        policy_html = policy_badges(c)
        action, action_detail, action_cls = candidate_action_line(c, b, flags)
        risk_html = risk_chip(flags[0], compact=True) if flags else '<span class="inline-flex px-1.5 py-0.5 rounded border text-[11px] font-semibold bg-emerald-50 text-emerald-700 border-emerald-200">暂无红旗</span>'
        shares = b.get("shares_estimate")
        shares_line = f"参考 ≤{int(shares)} 股" if shares else "参考股数待算"
        weight_line = f"模型上限 {fmt_weight(b.get('v6_weight'))}"
        ref_price = b.get("price_local") if b.get("price_local") is not None else c.get("entry_price")
        price_line = f"{fmt_num(ref_price, 2)} USD" if ref_price is not None else "价格待更新"
        rec_rank = c.get("rank")
        rank_line = f"AI 推荐榜 #{int(rec_rank)}" if isinstance(rec_rank, (int, float)) else "AI 推荐榜排名待同步"
        candidate_rows.append(f"""
          <tr class="border-b border-slate-100 last:border-0 align-top">
            <td class="py-3 pr-3 text-center">
              <span class="inline-flex items-center justify-center w-7 h-7 rounded-full bg-slate-900 text-white text-xs font-bold">{idx}</span>
              <div class="text-[10px] text-slate-400 mt-1 leading-tight">配仓顺序</div>
            </td>
            <td class="py-3 pr-3">
              <div class="font-mono font-bold text-slate-900">{html_lib.escape(ticker)}</div>
              <div class="text-[11px] text-slate-500 truncate max-w-[180px]">{html_lib.escape(str(c.get('name') or b.get('name') or ''))}</div>
              <div class="text-[11px] text-amber-700 mt-1">{html_lib.escape(rank_line)}</div>
              <div class="text-[11px] text-slate-500 mt-1">{html_lib.escape(price_line)}</div>
            </td>
            <td class="py-3 pr-3 text-xs text-slate-700 min-w-[230px]">
              <div class="font-semibold text-slate-900">{html_lib.escape(why_line)}</div>
              <div class="flex flex-wrap gap-1 mt-1">{factor_badges}</div>
              <div class="flex flex-wrap gap-1 mt-1">{policy_html}</div>
            </td>
            <td class="py-3 pr-3 text-xs text-slate-700 min-w-[190px]">
              <span class="inline-flex px-2 py-0.5 rounded border text-xs font-semibold {action_cls}">{html_lib.escape(action)}</span>
              <div class="mt-1">{html_lib.escape(action_detail)}</div>
              <div class="text-slate-500 mt-1">{html_lib.escape(weight_line)} · {html_lib.escape(shares_line)}</div>
            </td>
            <td class="py-3 text-xs">{risk_html}</td>
          </tr>
""")
    if not candidate_rows:
        candidate_rows.append("""
          <tr><td colspan="5" class="py-6 text-center text-sm text-slate-500">暂无今晚候选；请先运行 AI 推荐生成链路。</td></tr>
""")

    risk_alerts = []
    seen_risks = set()
    for h in holding_items:
        sym = str(h.get("symbol") or h.get("code") or "")
        for flag in (h.get("risk_flags") or [])[:1]:
            msg = flag_message(flag)
            key = ("hold", sym, msg)
            if msg and key not in seen_risks:
                seen_risks.add(key)
                risk_alerts.append(("持仓", sym, flag))
    for c in us_candidates[:20]:
        ticker = str(c.get("ticker") or c.get("code") or "")
        for flag in (c.get("risk_flags") or [])[:1]:
            msg = flag_message(flag)
            key = ("candidate", ticker, msg)
            if msg and key not in seen_risks:
                seen_risks.add(key)
                risk_alerts.append(("候选", ticker, flag))

    def risk_kind_badge(kind: str) -> str:
        if kind == "持仓":
            cls = "bg-emerald-50 text-emerald-700 border-emerald-200"
            title = "来自你的真实持仓，先按纪律线复查"
        else:
            cls = "bg-sky-50 text-sky-700 border-sky-200"
            title = "来自 AI 推荐/配仓候选，不是你的真实持仓"
        return (
            f'<span class="mt-0.5 inline-flex items-center justify-center w-12 shrink-0 rounded-full border px-2 py-0.5 '
            f'text-[11px] font-bold {cls}" title="{html_lib.escape(title, quote=True)}">'
            f'{html_lib.escape(kind)}</span>'
        )

    risk_alert_rows = []
    for kind, ticker, flag in risk_alerts[:6]:
        risk_alert_rows.append(f"""
          <div class="flex items-start gap-3 py-2 border-b border-slate-100 last:border-0">
            {risk_kind_badge(kind)}
            <span class="font-mono font-bold text-slate-900 w-20 shrink-0">{html_lib.escape(ticker)}</span>
            <div class="text-xs">{risk_chip(flag)}</div>
          </div>
""")
    if not risk_alert_rows:
        risk_alert_rows.append('<div class="py-3 text-sm text-slate-500">当前首屏候选和持仓未命中结构化高风险；仍需逐票买前审查。</div>')

    attention_items = []
    if blocking:
        attention_items.append(attention_item("今天不能直接按推荐交易", overall_text, "#runtime-status", "rose"))
    for h in holding_items:
        symbol = str(h.get("symbol") or h.get("code") or "?").upper()
        discipline = h.get("discipline") or {}
        if isinstance(discipline, dict) and discipline.get("triggered"):
            attention_items.append(attention_item(
                f"{symbol} 纪律线已触发",
                f"{discipline.get('action_label') or '需要处理'} · {discipline.get('suggested_size_text') or '先复查'}",
                "#real-holdings",
                "rose",
            ))
    held_symbols = {str(h.get("symbol") or h.get("code") or "").upper() for h in holding_items}
    appearance = _runtime_load_json("data/latest/picks_appearance.json") or {}
    tickers_appearance = appearance.get("tickers") or {}
    movement_new_count = 0
    movement_rise_count = 0
    for _tk, info in tickers_appearance.items():
        try:
            if int(info.get("count") or 0) == 1:
                movement_new_count += 1
            rank_up = float(info.get("rank_up") or 0)
            score_up = float(info.get("score_up") or 0)
            if rank_up >= 3 or score_up >= 2:
                movement_rise_count += 1
        except Exception:
            continue
    dropouts = appearance.get("dropouts") or []
    held_dropouts = [d for d in dropouts if str(d.get("ticker") or "").upper() in held_symbols]
    for d in held_dropouts[:2]:
        attention_items.append(attention_item(
            f"{str(d.get('ticker') or '').upper()} 跌出推荐",
            f"上次第 {d.get('prev_rank') or '—'} 名；真实持仓先按纪律线复查。",
            "#real-holdings",
            "amber",
        ))
    for kind, ticker, flag in risk_alerts[:3]:
        attention_items.append(attention_item(
            f"{ticker} {flag_label(flag)}",
            short_text(flag_message(flag), 70),
            "#buy-research" if kind == "候选" else "#real-holdings",
            "rose" if flag_severity(flag) == "high" else "amber",
        ))
    if not attention_items:
        attention_items.append(attention_item("今天没有强制处理项", "持仓和首屏候选未触发强风险；按候选顺序做买前研究即可。", "", "emerald"))
    attention_html = "".join(attention_items[:5])

    movement_summary_html = f"""
      <div class="grid grid-cols-2 sm:grid-cols-4 gap-2">
        <div class="rounded-lg border border-violet-100 bg-violet-50 px-3 py-2">
          <div class="text-[11px] text-violet-700">新进推荐</div>
          <div class="text-xl font-bold text-violet-900">{movement_new_count}</div>
        </div>
        <div class="rounded-lg border border-amber-100 bg-amber-50 px-3 py-2">
          <div class="text-[11px] text-amber-700">排名跃升</div>
          <div class="text-xl font-bold text-amber-900">{movement_rise_count}</div>
        </div>
        <div class="rounded-lg border border-rose-100 bg-rose-50 px-3 py-2">
          <div class="text-[11px] text-rose-700">跌出推荐</div>
          <div class="text-xl font-bold text-rose-900">{len(dropouts)}</div>
        </div>
        <div class="rounded-lg border border-orange-100 bg-orange-50 px-3 py-2">
          <div class="text-[11px] text-orange-700">持仓触及</div>
          <div class="text-xl font-bold text-orange-900">{len(held_dropouts)}</div>
        </div>
      </div>
"""

    if blocking:
        decision_label = "只读观察"
        decision_detail = "质量闸门或生产验收失败，今天不要按推荐直接交易。"
        decision_cls = "border-rose-200 bg-rose-50 text-rose-900"
        primary_action = "先看系统状态"
    elif risk_alerts:
        decision_label = "谨慎观察"
        decision_detail = "系统可用，但持仓/候选里有结构化风险；先按纪律线和买前研究过滤。"
        decision_cls = "border-amber-200 bg-amber-50 text-amber-900"
        primary_action = "只做小批、分批、先复查风险"
    else:
        decision_label = "可研究"
        decision_detail = "系统链路可用；候选可以进入买前研究，但不等于自动下单。"
        decision_cls = "border-emerald-200 bg-emerald-50 text-emerald-900"
        primary_action = "从前 3-5 只候选开始"

    # 📅 本周市场事件 — 来自 junior_stock_radar.json（三市场聚合）
    radar = _runtime_load_json("data/latest/junior_stock_radar.json") or {}
    summary = radar.get("summary_week") or {}
    cn_s = summary.get("cn") or {}
    us_s = summary.get("us") or {}
    cn_sub_n = int(cn_s.get("subscribe_count") or 0)
    cn_lis_n = int(cn_s.get("listing_count") or 0)
    cn_unl_n = int(cn_s.get("unlock_count") or 0)
    cn_unl_pool_n = int(cn_s.get("unlock_in_pool_count") or 0)
    cn_pool_items = cn_s.get("unlock_in_pool_codes") or []
    cn_junior_top = cn_s.get("junior_top3") or []
    us_priced_n = int(us_s.get("priced_7d_count") or 0)
    us_filed_n = int(us_s.get("filed_7d_count") or 0)
    us_junior_n = int(us_s.get("junior_count") or 0)
    us_broken_n = int(us_s.get("broken_count") or 0)
    us_ipo_top = us_s.get("ipo_top3") or []
    us_junior_top = us_s.get("junior_top3") or []
    radar_generated = str(radar.get("generated_at") or "")[:19] if radar else ""

    cn_pool_line = ""
    if cn_pool_items:
        bits = [f"{html_lib.escape(x.get('name') or '')} ({html_lib.escape(x.get('code') or '')}, {html_lib.escape(str(x.get('date') or ''))})"
                for x in cn_pool_items[:3]]
        cn_pool_line = f"<div class='text-xs text-rose-700 mt-2'>⚠️ A 股池子内本周解禁: {' · '.join(bits)}</div>"
    elif cn_unl_n > 0:
        cn_pool_line = "<div class='text-xs text-emerald-700 mt-2'>✓ A 股本周解禁未触及你的持仓 / 自选股。</div>"

    cn_junior_line = ""
    if cn_junior_top:
        bits = [f"{html_lib.escape(x.get('name') or '')} ({html_lib.escape(x.get('code') or '')}, 分 {x.get('score', 0)})"
                for x in cn_junior_top[:3]]
        cn_junior_line = f"<div class='text-xs text-slate-600 mt-1'>🎯 A 股 Top 次新: {' · '.join(bits)}</div>"

    us_ipo_line = ""
    if us_ipo_top:
        bits = [f"{html_lib.escape(x.get('symbol') or '')} ({html_lib.escape(str(x.get('date') or ''))})"
                for x in us_ipo_top[:3]]
        us_ipo_line = f"<div class='text-xs text-slate-600 mt-1'>🇺🇸 美股本周新上市: {' · '.join(bits)}</div>"
    us_junior_line = ""
    if us_junior_top:
        bits = [f"{html_lib.escape(x.get('symbol') or '')} ({x.get('vs_issue_pct', 0)}%, 分 {x.get('score', 0)})"
                for x in us_junior_top[:3]]
        us_junior_line = f"<div class='text-xs text-slate-600 mt-1'>🎯 美股 Top 次新: {' · '.join(bits)}</div>"

    if radar:
        market_events_html = f"""
  <div class="mt-6 bg-white rounded-xl border border-slate-200 p-4">
    <div class="flex items-start justify-between gap-3 flex-wrap">
      <div class="flex-1">
        <div class="flex items-center gap-2 mb-1">
          <span>📅</span>
          <h3 class="font-bold text-slate-900">本周市场事件</h3>
          <span class="text-[10px] text-slate-400">{html_lib.escape(radar_generated)}</span>
        </div>
        <div class="text-sm text-slate-700">
          <span class="font-semibold text-slate-900">🇨🇳 A 股</span>:
          申购 <span class="font-semibold text-violet-700">{cn_sub_n}</span> ·
          上市 <span class="font-semibold text-violet-700">{cn_lis_n}</span> ·
          解禁 <span class="font-semibold {'text-rose-700' if cn_unl_pool_n else 'text-slate-700'}">{cn_unl_n}</span> 只
          {f'<span class="text-rose-700">(池子内 {cn_unl_pool_n})</span>' if cn_unl_pool_n else ''}
          &nbsp;·&nbsp;
          <span class="font-semibold text-slate-900">🇺🇸 美股</span>:
          定价 <span class="font-semibold text-violet-700">{us_priced_n}</span> ·
          申报 <span class="font-semibold text-violet-700">{us_filed_n}</span> ·
          次新池 <span class="font-semibold text-violet-700">{us_junior_n}</span>(破发 {us_broken_n})
          &nbsp;·&nbsp;
          <span class="font-semibold text-slate-900">🇭🇰 港股</span>:
          <span class="text-slate-400">数据未接入</span>
        </div>
        {cn_pool_line}
        {us_ipo_line}
        {us_junior_line}
        {cn_junior_line}
      </div>
      <a href="#ipo-junior" class="text-xs font-medium text-violet-700 hover:text-violet-900 whitespace-nowrap">打开 IPO & 次新股 →</a>
    </div>
  </div>
"""
    else:
        market_events_html = """
  <div class="mt-6 bg-white rounded-xl border border-slate-200 p-4 text-sm text-slate-500">
    📅 本周市场事件：IPO / 次新股雷达已暂停，暂无缓存数据。
  </div>
"""

    empty_state_banner = ""
    if blocking or not discovery_n or not pool_total:
        banner_detail = (
            f"系统池 {pool_total} 只 · 池成员 {pool_membership} 只 · "
            f"行情覆盖 {coverage.get('priced', 0)}/{coverage.get('active_pool', 0)} ({coverage.get('pct', 0)}%)。"
        )
