def _find_plan_inception_date() -> str | None:
    """DuckDB 里最早的 v6 plan snapshot 日期（YYYY-MM-DD）—— 即 v6 方向定下来那天。"""
    db_path = _duckdb_path()
    if os.path.exists(db_path):
        try:
            import duckdb
            con = duckdb.connect(db_path, read_only=True)
            row = con.execute(
                "SELECT MIN(taken_at) FROM snapshots "
                "WHERE category='optimize' AND name='plan_v6'"
            ).fetchone()
            con.close()
            if row and row[0]:
                return str(row[0])[:10]
        except Exception:
            pass
    try:
        with open(os.path.join(_REPO, "data", "latest", "plan_a_v5.json")) as f:
            return (json.load(f).get("generated_at") or "")[:10] or None
    except Exception:
        return None


def _load_inception_plan_from_duckdb() -> dict | None:
    """读 DuckDB plan_v6 最早一条 payload —— inception 那天的原始 plan。

    用来给 compute_plan_forward_track() 提供"冻结在锁定日"的 tickers，
    避免 look-ahead bias：之前用今天最新 plan_a_v5.json 的 tickers + 5-08 锚定，
    会把后换入的股票回填到锁定日轨迹里（不可实操、用了未来信息）。
    """
    db_path = _duckdb_path()
    if not os.path.exists(db_path):
        return None
    try:
        import duckdb
        con = duckdb.connect(db_path, read_only=True)
        row = con.execute(
            "SELECT payload FROM snapshots "
            "WHERE category='optimize' AND name='plan_v6' "
            "ORDER BY taken_at ASC LIMIT 1"
        ).fetchone()
        con.close()
        if row and row[0]:
            return json.loads(row[0]) if isinstance(row[0], str) else row[0]
    except Exception:
        pass
    return None


def _load_plan_v6_at_or_before(date_str: str) -> dict | None:
    """读 DuckDB plan_v6 在 date_str 当天（含）及之前的最新一条 payload。

    用于 P1 动态 rebalance：每周一找"截至本周一最新的推荐方案"调仓。
    若当天没有快照（系统未跑日 / 节假日），自然 fallback 到上一次落库的方案。
    """
    db_path = _duckdb_path()
    if not os.path.exists(db_path):
        return None
    try:
        import duckdb
        con = duckdb.connect(db_path, read_only=True)
        row = con.execute(
            "SELECT payload FROM snapshots "
            "WHERE category='optimize' AND name='plan_v6' "
            "AND taken_at <= CAST(? AS TIMESTAMP) + INTERVAL 1 DAY - INTERVAL 1 SECOND "
            "ORDER BY taken_at DESC LIMIT 1",
            [date_str]
        ).fetchone()
        con.close()
        if row and row[0]:
            return json.loads(row[0]) if isinstance(row[0], str) else row[0]
    except Exception:
        pass
    return None


def _extract_plan_weights(plan: dict) -> dict:
    """从 plan payload 抽出 {ticker: normalized_weight}，处理 v5/v6/plan 三种字段名 + 各种 weight 字段。"""
    if not plan or not isinstance(plan, dict):
        return {}
    plan_list = plan.get("plan_v5") or plan.get("plan_v6") or plan.get("plan") or []
    raw = []
    for p in plan_list:
        t = p.get("ticker")
        w = (p.get("v5_weight") or p.get("v6_weight") or p.get("weight")
             or p.get("target_weight") or p.get("capped_weight") or 0.0)
        if t and w and float(w) > 0:
            raw.append((t, float(w)))
    if not raw:
        return {}
    total = sum(w for _, w in raw) or 1.0
    return {t: w / total for t, w in raw}


def compute_dynamic_rebalance_track(history: dict, benchmark: str = "SPY",
                                     commission_per_movement: float = 0.0005,
                                     rebalance_dow: int = 0) -> dict:
    """P1 + P2 动态 rebalance NAV 跟踪（C 类设计）。

    用户实际用法：每周一根据系统最新推荐换仓。这条曲线反映"持续按 AI 推荐调仓"
    的真实回报，与 compute_plan_forward_track() 的"buy-and-hold 死守"对照看，
    差距 = AI 持续动态选股带来的真实价值（P2 双曲线对比的核心）。

    参数：
      • commission_per_movement: 每"流动 1 元"的手续费成本（默认 5 bps）。
        一次"卖 ¥1000 of A + 买 ¥1000 of B"的 swap，total_movement = ¥2000，
        cost = ¥2000 × 0.0005 = ¥1 = 0.10% 完整 round-trip。涵盖 spread + 印花税
        粗略估算（A 股稍高，美股稍低，取中间值）。
      • rebalance_dow: 每周哪一天 rebalance（0=Monday）；周一节假日时自动顺延到本周
        第一个交易日。
    """
    if not history or "tickers" not in history:
        return {}

    inception_date = _find_plan_inception_date()
    if not inception_date:
        return {}

    inception_plan = _load_inception_plan_from_duckdb()
    if not inception_plan:
        return {}

    initial_weights = _extract_plan_weights(inception_plan)
    if not initial_weights:
        return {}

    tickers_data = history["tickers"]

    # 构造 ticker → {date_str: close} 加速查询
    ticker_close: dict[str, dict[str, float]] = {}
    for tkr, d in tickers_data.items():
        if d and d.get("ts") and d.get("close"):
            ticker_close[tkr] = {
                ts: float(c) for ts, c in zip(d["ts"], d["close"]) if c is not None
            }

    # common_dates：所有 initial_tickers 都有价格的日期交集
    common: set | None = None
    for tkr in initial_weights:
        if tkr not in ticker_close:
            continue
        ts_set = set(ticker_close[tkr].keys())
        common = ts_set if common is None else (common & ts_set)
    if not common:
        return {"inception_date": inception_date, "error": "no common dates in initial plan"}

    common_dates = sorted(common)

    # baseline_idx：最后一个 ≤ inception_date 的交易日
    baseline_idx = None
    for i, d in enumerate(common_dates):
        if d <= inception_date:
            baseline_idx = i
        else:
            break
    if baseline_idx is None:
        baseline_idx = 0
    baseline_date = common_dates[baseline_idx]

    # 在 baseline 那天按 inception plan 建仓
    holdings: dict[str, float] = {}
    for t, w in initial_weights.items():
        p0 = ticker_close.get(t, {}).get(baseline_date)
        if p0 and p0 > 0:
            holdings[t] = w / p0  # NAV=1.0 → shares = w / price

    # 用 context_days 之前作为图表上下文（虚线），跟 static 函数对齐
    context_days = 30
    win_start = max(0, baseline_idx - context_days)
    win_dates = common_dates[win_start:]
    rel_baseline = baseline_idx - win_start

    from datetime import datetime as _dt

    def _iso_week(date_str: str) -> tuple[int, int]:
        """返回 (iso_year, iso_week)，跨年周一也算同一周。"""
        y, m, d = date_str.split("-")
        return _dt(int(y), int(m), int(d)).isocalendar()[:2]

    # rebalance 触发：今天的 iso-week 跟上一个交易日不同（即跨周了）
    # 等价于"本周的第一个交易日就 rebalance"，自然处理周一节假日顺延
    nav_list: list[float | None] = []
    rebalance_log: list[dict] = []
    rebalance_dates_used: list[str] = []
    total_commission = 0.0
    prev_iso_week: tuple[int, int] | None = None

    # 先在 win_start..baseline 段填 None（context 段，不算 NAV）
    for _ in range(rel_baseline):
        nav_list.append(None)

    # 从 baseline 开始算
    for i in range(baseline_idx, len(common_dates)):
        date = common_dates[i]
        cur_iso = _iso_week(date)

        # 当前 NAV（rebalance 前）
        current_value = 0.0
        for t, shares in holdings.items():
            p = ticker_close.get(t, {}).get(date)
            if p is not None:
                current_value += shares * p

        # rebalance：跨周（prev_iso_week 存在且不同）且今天 != baseline 那天
        if prev_iso_week is not None and cur_iso != prev_iso_week and date != baseline_date:
            new_plan = _load_plan_v6_at_or_before(date)
            new_weights = _extract_plan_weights(new_plan) if new_plan else {}
            # 过滤掉今天没有价格数据的 tickers
            available_w = {t: w for t, w in new_weights.items()
                           if t in ticker_close and date in ticker_close[t]}
            wsum = sum(available_w.values())
            if available_w and wsum > 0 and current_value > 0:
                available_w = {t: w / wsum for t, w in available_w.items()}
                new_alloc = {t: w * current_value for t, w in available_w.items()}
                old_alloc = {t: holdings.get(t, 0) * ticker_close.get(t, {}).get(date, 0)
                             for t in (set(holdings.keys()) | set(available_w.keys()))}
                all_t = set(new_alloc.keys()) | set(old_alloc.keys())
                total_movement = sum(abs(new_alloc.get(t, 0) - old_alloc.get(t, 0)) for t in all_t)
                cost = total_movement * commission_per_movement
                post_value = current_value - cost
                total_commission += cost

                new_holdings: dict[str, float] = {}
                for t, w in available_w.items():
                    p_t = ticker_close[t][date]
                    new_holdings[t] = w * post_value / p_t

                rebalance_log.append({
                    "date": date,
                    "pre_nav": round(current_value, 6),
                    "post_nav": round(post_value, 6),
                    "turnover_dollar": round(total_movement, 6),
                    "commission_dollar": round(cost, 6),
                    "n_tickers": len(available_w),
                    "tickers_added": sorted(set(available_w.keys()) - set(holdings.keys())),
                    "tickers_removed": sorted(set(holdings.keys()) - set(available_w.keys())),
                })
                holdings = new_holdings
                current_value = post_value
                rebalance_dates_used.append(date)

        nav_list.append(current_value)
        prev_iso_week = cur_iso

    # 基准 SPY（同样锚到 baseline）
    bench_nav: list[float | None] = []
    bench_d = ticker_close.get(benchmark, {})
    b_anchor = bench_d.get(baseline_date) if bench_d else None
    if bench_d and b_anchor:
        last_b = 1.0
        for d in win_dates:
            v = bench_d.get(d)
            if v and b_anchor:
                last_b = v / b_anchor
            bench_nav.append(last_b)

    # tracked 段（baseline 之后）算指标
    tracked = [v for v in nav_list[rel_baseline:] if v is not None]
    tracked_dates = win_dates[rel_baseline:rel_baseline + len(tracked)]
    bench_tracked = bench_nav[rel_baseline:rel_baseline + len(tracked)] if bench_nav else []

    import math
    def _daily_rets(curve: list[float]) -> list[float]:
        return [0.0] + [
            (curve[i] / curve[i - 1] - 1.0) if curve[i - 1] else 0.0
            for i in range(1, len(curve))
        ]

    def _max_dd(curve: list[float]) -> float:
        if not curve: return 0.0
        peak = curve[0]; mdd = 0.0
        for v in curve:
            if v > peak: peak = v
            dd = (v - peak) / peak if peak else 0.0
            if dd < mdd: mdd = dd
        return mdd

    n_tracked = max(0, len(tracked) - 1)
    daily_rets = _daily_rets(tracked) if tracked else []
    # 锚到 tracked[0] / bench_tracked[0]：当 inception plan 中部分 ticker 缺 history 时
    # 初始 NAV ≠ 1.0；硬减 1.0 会把"缺数据"渲染成虚假亏损。
    cumret = (tracked[-1] / tracked[0] - 1.0) if len(tracked) >= 1 and tracked[0] else 0.0
    bench_cumret = (bench_tracked[-1] / bench_tracked[0] - 1.0) if len(bench_tracked) >= 1 and bench_tracked[0] else 0.0
    if n_tracked > 0:
        r_avg = sum(daily_rets[1:]) / n_tracked
        r_var = sum((r - r_avg) ** 2 for r in daily_rets[1:]) / max(1, n_tracked - 1) if n_tracked >= 2 else 0
        r_std = math.sqrt(r_var)
        annvol = r_std * math.sqrt(252)
        sharpe = (r_avg * 252) / annvol if annvol > 1e-9 else 0.0
        win_days = sum(1 for r in daily_rets[1:] if r > 0)
        win_rate = win_days / n_tracked
        annret = (1 + cumret) ** (252 / n_tracked) - 1.0 if n_tracked > 0 else 0.0
    else:
        annvol = sharpe = win_rate = annret = 0.0
        win_days = 0

    universe = set(initial_weights.keys())
    for r in rebalance_log:
        universe.update(r["tickers_added"])

    return {
        "dates": win_dates,
        "nav": [round(v, 6) if v is not None else None for v in nav_list],
        "bench_nav": [round(v, 6) for v in bench_nav] if bench_nav else [],
        "benchmark": benchmark if bench_nav else None,
        "inception_date": inception_date,
        "baseline_date": baseline_date,
        "baseline_idx_in_window": rel_baseline,
        "rebalance_dates": rebalance_dates_used,
        "rebalance_log": rebalance_log,
        "total_commission": round(total_commission, 6),
        "total_commission_pct": round(total_commission * 100, 4),
        "commission_per_movement_bps": round(commission_per_movement * 10000, 1),
        "rebalance_freq": "weekly_monday",
        "tickers_universe": sorted(universe),
        "metrics": {
            "n_tracked_days": n_tracked,
            "tracked_start": tracked_dates[1] if len(tracked_dates) > 1 else None,
            "tracked_end": tracked_dates[-1] if tracked_dates else None,
            "cumulative_return_pct": round(cumret * 100, 2),
            "bench_cumulative_return_pct": round(bench_cumret * 100, 2),
            "alpha_pct": round((cumret - bench_cumret) * 100, 2),
            "annual_return_pct": round(annret * 100, 2),
            "annual_vol_pct": round(annvol * 100, 2),
            "sharpe": round(sharpe, 2),
            "max_drawdown_pct": round(_max_dd(tracked) * 100, 2),
            "win_rate_pct": round(win_rate * 100, 1),
            "win_days": win_days,
            "total_days": n_tracked,
            "n_rebalances": len(rebalance_log),
        },
    }


def compute_plan_forward_track(plan: dict, history: dict, benchmark: str = "SPY",
                                context_days: int = 30) -> dict:
    """从 plan 锁定日往后跟踪真实表现（forward 视角）。

    思路：
      • inception_date = v6 plan 第一次落库的日期（方向定下来那天）
      • baseline_date  = history 中 ≤ inception_date 的最后一个交易日 → NAV=100 锚点
      • context window = baseline_date 之前 N 个交易日（仅作视觉上下文，灰色虚线）
      • tracked window = baseline_date 之后的所有交易日（真实实盘营收）

    指标只在 tracked 段算；context 仅供图表参考。
    刚锁定时 tracked = 0 天，曲线只有 context + 锁定基线点；每日 daily_refresh 自动累加。
    """
    if not plan or not isinstance(plan, dict):
        return {}
    if not history or "tickers" not in history:
        return {}

    # P0 修复 look-ahead bias（2026-05-10）：tickers 从 DuckDB inception 那天的 plan 读，
    # 不再用传入的"今天最新 plan_a_v5.json"——避免把后换入的股票回填到锁定日轨迹。
    inception_plan = _load_inception_plan_from_duckdb()
    if inception_plan:
        src_plan = inception_plan
        tickers_source = "duckdb_inception"
    else:
        # fallback：DuckDB 还没数据时用传入的 plan（首次部署兜底）
        src_plan = plan
        tickers_source = "latest_plan_a_v5_fallback"

    plan_list = src_plan.get("plan_v5") or src_plan.get("plan_v6") or src_plan.get("plan") or []
    if not plan_list:
        return {}

    inception_date = _find_plan_inception_date()
    tickers_data = history["tickers"]

    raw = [(p.get("ticker"), float(p.get("v5_weight") or p.get("weight") or p.get("target_weight") or 0.0))
           for p in plan_list if p.get("ticker")]
    total_w = sum(w for _, w in raw) or 1.0
    weights = [(t, w / total_w) for t, w in raw if w > 0]

    used: list[tuple[str, float, list[str], list[float]]] = []
    missing = []
    for tkr, w in weights:
        d = tickers_data.get(tkr)
        if not d or not d.get("ts") or not d.get("close"):
            missing.append(tkr)
            continue
        # 容错：close 序列里可能有 None（节假日 / yfinance 偶发漏值），筛掉再保留 ts ↔ close 对齐
        close_clean = []
        ts_clean = []
        for t, c in zip(d["ts"], d["close"]):
            if c is None:
                continue
            try:
                close_clean.append(float(c))
                ts_clean.append(t)
            except (TypeError, ValueError):
                continue
        if not close_clean:
            missing.append(tkr)
            continue
        used.append((tkr, w, ts_clean, close_clean))

    if not used:
        return {"tickers_missing": missing, "tickers_used": [], "inception_date": inception_date}

    common = set(used[0][2])
    for _, _, ts, _ in used[1:]:
        common &= set(ts)
    common_dates = sorted(common)
    if not common_dates:
        return {"tickers_missing": missing, "tickers_used": [t for t, *_ in used], "inception_date": inception_date}

    aligned = []
    for tkr, w, ts, close in used:
        ts_to_close = dict(zip(ts, close))
        aligned_close = [ts_to_close[d] for d in common_dates]
        aligned.append((tkr, w, aligned_close))

    # 找 baseline_date：最后一个 <= inception 的交易日
    baseline_idx = None
    if inception_date:
        for i, d in enumerate(common_dates):
            if d <= inception_date:
                baseline_idx = i
            else:
                break
    if baseline_idx is None:
        # plan 锁定在 history 最早日期之前 → 用最早日期
        baseline_idx = 0

    # window：[baseline-context_days, end]
    win_start = max(0, baseline_idx - context_days)
    win_dates = common_dates[win_start:]
    rel_baseline = baseline_idx - win_start  # 在 win_dates 中的位置

    # NAV：以 baseline 那天的收盘为锚点（NAV[baseline]=1.0）
    nav = []
    for i in range(win_start, len(common_dates)):
        v = sum(w * (closes[i] / closes[baseline_idx]) for _, w, closes in aligned)
        nav.append(v)

    # 基准 SPY，同样锚到 baseline 日期
    bench_nav = []
    bench_d = tickers_data.get(benchmark)
    if bench_d and bench_d.get("ts") and bench_d.get("close"):
        bts_to_close = dict(zip(bench_d["ts"], [float(c) for c in bench_d["close"]]))
        baseline_date = common_dates[baseline_idx]
        b_anchor = bts_to_close.get(baseline_date)
        if b_anchor:
            for d in win_dates:
                if d in bts_to_close:
                    bench_nav.append(bts_to_close[d] / b_anchor)
                else:
                    bench_nav.append(None)
            # 把 None 用前值填充（防止图断线）
            last = 1.0
            bench_nav = [(last := v) if v is not None else last for v in bench_nav]

    # 仅 tracked 段（baseline 之后）算指标
    tracked_nav = nav[rel_baseline:]
    tracked_bench = bench_nav[rel_baseline:] if bench_nav else []
    tracked_dates = win_dates[rel_baseline:]

    def _daily_rets(curve):
        return [0.0] + [
            (curve[i] / curve[i - 1] - 1.0) if curve[i - 1] else 0.0
            for i in range(1, len(curve))
        ]

    daily_rets_full = _daily_rets(nav)
    daily_rets_tracked = _daily_rets(tracked_nav)

    def _max_dd(curve):
        if not curve: return 0.0
        peak = curve[0]; mdd = 0.0
        for v in curve:
            if v > peak: peak = v
            dd = (v - peak) / peak if peak else 0.0
            if dd < mdd: mdd = dd
        return mdd

    n_tracked = max(0, len(tracked_dates) - 1)  # 锁定日不算 1 天，从锁定日次日起算
    days_per_year = 252
    # 锚到 tracked[0] / bench_tracked[0]：与 dynamic 版本同一理由（避免缺数据 ticker 渲染成假亏损）。
    cumret = (tracked_nav[-1] / tracked_nav[0] - 1.0) if len(tracked_nav) > 1 and tracked_nav[0] else 0.0
    bench_cumret = (tracked_bench[-1] / tracked_bench[0] - 1.0) if len(tracked_bench) > 1 and tracked_bench[0] else 0.0
    import math
    if n_tracked > 0:
        r_avg = sum(daily_rets_tracked[1:]) / n_tracked
        r_var = sum((r - r_avg) ** 2 for r in daily_rets_tracked[1:]) / max(1, n_tracked - 1) if n_tracked >= 2 else 0
        r_std = math.sqrt(r_var)
        annvol = r_std * math.sqrt(days_per_year)
        sharpe = (r_avg * days_per_year) / annvol if annvol > 1e-9 else 0.0
        win_days = sum(1 for r in daily_rets_tracked[1:] if r > 0)
        win_rate = win_days / n_tracked
        annret = (1 + cumret) ** (days_per_year / n_tracked) - 1.0 if n_tracked > 0 else 0.0
    else:
        annvol = sharpe = win_rate = annret = 0.0
        win_days = 0

    # 单股贡献：用 baseline → 最新收盘
    last_idx = len(common_dates) - 1

    # ticker → 公司名：优先用 prices 快照（319 只全集，A 股中文 + 美股英文），
    # audit 快照只在 picks_audit 触发时才有内容，单独用会大面积缺失。
    name_map: dict = {}
    try:
        prices_dir = os.path.join(_REPO, "data", "snapshots", "prices")
        if os.path.isdir(prices_dir):
            price_files = sorted([f for f in os.listdir(prices_dir)
                                   if f.startswith("prices_") and f.endswith(".json")],
                                  reverse=True)
            if price_files:
                with open(os.path.join(prices_dir, price_files[0]), encoding="utf-8") as pf:
                    prices = json.load(pf)
                    if isinstance(prices, list):
                        name_map = {r.get("code"): r.get("name") for r in prices
                                    if r.get("code") and r.get("name")}
    except Exception:
        pass
    try:
        audit_dir = os.path.join(_REPO, "data", "snapshots", "audit")
        if os.path.isdir(audit_dir):
            audit_files = sorted([f for f in os.listdir(audit_dir)
                                   if f.startswith("audit_") and f.endswith(".json")],
                                  reverse=True)
            if audit_files:
                with open(os.path.join(audit_dir, audit_files[0]), encoding="utf-8") as af:
                    audit = json.load(af)
                    if isinstance(audit, list):
                        for r in audit:
                            t, n = r.get("ticker"), r.get("name")
                            if t and n and t not in name_map:
                                name_map[t] = n
    except Exception:
        pass

    per_ticker = []
    name_hits = 0
    for tkr, w, closes in aligned:
        first, last = closes[baseline_idx], closes[last_idx]
        tret = (last / first - 1.0) if first else 0.0
        nm = name_map.get(tkr, "")
        if nm:
            name_hits += 1
        per_ticker.append({
            "ticker": tkr,
            "name": nm,
            "weight": round(w, 4),
            "close_first": round(first, 2),
            "close_last": round(last, 2),
            "return_pct": round(tret * 100, 2),
            "contribution_pct": round(w * tret * 100, 2),
        })
    per_ticker.sort(key=lambda x: -x["contribution_pct"])
    name_total = len(per_ticker)
    name_hit_rate = (name_hits / name_total) if name_total else 1.0

    return {
        "inception_date": inception_date,
        "baseline_date": common_dates[baseline_idx],
        "baseline_idx_in_window": rel_baseline,
        "dates": win_dates,
        "nav": [round(v, 6) for v in nav],
        "bench_nav": [round(v, 6) for v in bench_nav] if bench_nav else [],
        "daily_returns": [round(r * 100, 4) for r in daily_rets_full],
        "benchmark": benchmark if bench_nav else None,
        "metrics": {
            "n_tracked_days": n_tracked,
            "tracked_start": tracked_dates[0] if tracked_dates else None,
            "tracked_end": tracked_dates[-1] if tracked_dates else None,
            "cumulative_return_pct": round(cumret * 100, 2),
            "bench_cumulative_return_pct": round(bench_cumret * 100, 2),
            "alpha_pct": round((cumret - bench_cumret) * 100, 2),
            "annual_return_pct": round(annret * 100, 2),
            "annual_vol_pct": round(annvol * 100, 2),
            "sharpe": round(sharpe, 2),
            "max_drawdown_pct": round(_max_dd(tracked_nav) * 100, 2),
            "win_rate_pct": round(win_rate * 100, 1),
            "win_days": win_days,
            "total_days": n_tracked,
        },
        "per_ticker": per_ticker,
        "tickers_used": [t for t, *_ in aligned],
        "tickers_missing": missing,
        "tickers_source": tickers_source,  # P0：标识 tickers 来源（duckdb_inception 或 latest_plan_a_v5_fallback）
        "name_resolution": {
            "hits": name_hits,
            "total": name_total,
            "hit_rate": round(name_hit_rate, 3),
        },
    }


# 兼容旧调用名（一段时间后清理）
compute_plan_backtest = compute_plan_forward_track


def load_audit_snapshot():
    """读最新一次 picks 反向审查快照（JSON 文件路径）。"""
    audit_dir = os.path.join(_REPO,
                             "data", "snapshots", "audit")
    if not os.path.isdir(audit_dir):
        return None
    files = sorted([f for f in os.listdir(audit_dir) if f.startswith("picks_audit_")],
                   reverse=True)
    if not files:
        return None
    try:
        with open(os.path.join(audit_dir, files[0]), encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return None


def load_audit_snapshot_from_db():
    """读最新一次 picks 反向审查快照（DuckDB snapshots 表）。"""
    db_path = _duckdb_path()
    if not os.path.exists(db_path):
        return None
    try:
        import duckdb
    except ImportError:
        return None
    try:
        con = duckdb.connect(db_path, read_only=True)
        row = con.execute(
            "SELECT payload FROM snapshots "
            "WHERE category=? AND name=? "
            "ORDER BY taken_at DESC LIMIT 1",
            ["audit", "picks_audit"],
        ).fetchone()
        con.close()
        if not row:
            return None
        payload = row[0]
        return json.loads(payload) if isinstance(payload, str) else payload
    except Exception as e:
        print(f"  ⚠️  从 DuckDB 读 picks_audit 失败: {e}")
        return None


def audit_panel_html(snap):
    """渲染 picks 反向审查面板（Risk Parity + 估值 + 13F + Markowitz）。"""
    if not snap:
        return """
<section id="audit-panel" class="max-w-7xl mx-auto px-6 py-10 bg-gradient-to-br from-slate-50 to-slate-100 rounded-2xl my-6">
  <div class="flex items-center gap-3 mb-2">
    <span class="text-3xl">🛡</span>
    <h2 class="text-2xl font-bold text-slate-900">风险反证 · 买前审查</h2>
  </div>
  <p class="text-slate-600">尚无审查快照。先跑：<code class="bg-slate-200 px-2 py-0.5 rounded">python3 -m stock_research.jobs.audit_picks_v2 --fast</code></p>
</section>
"""

    # 总评
    issues = []
    tc = snap.get("theme_concentration", {})
    if tc.get("level") == "严重":
        issues.append(f"主题严重失衡（{tc.get('top_theme')} 占 {tc.get('top_pct', 0):.0f}%）")
    if snap.get("valuation_sanity", {}).get("warn_count", 0) > 0:
        issues.append(f"{snap['valuation_sanity']['warn_count']} 只估值警告")
    if snap.get("thirteen_f_consistency", {}).get("warn_count", 0) > 0:
        issues.append(f"{snap['thirteen_f_consistency']['warn_count']} 只与 13F 矛盾")

    overall_color = "emerald" if not issues else ("amber" if len(issues) <= 2 else "rose")
    overall_text = "🟢 通过六项审查，无重大问题" if not issues else f"⚠️ 发现 {len(issues)} 项问题"

    # 1. 主题集中度（条形图）
    tc_html = ""
    if tc.get("status") == "ok":
        bars = []
        for d in tc.get("distribution", []):
            pct = d.get("pct", 0)
            bars.append(f'''
                <div class="flex items-center gap-2 text-xs mb-1">
                  <span class="w-32 truncate">{d.get("theme", "")}</span>
                  <span class="w-10 text-right text-slate-500">{d.get("n", 0)} 只</span>
                  <div class="flex-1 bg-slate-100 rounded h-3 relative overflow-hidden">
                    <div class="absolute left-0 top-0 h-full bg-violet-400" style="width:{pct}%"></div>
                  </div>
                  <span class="w-12 text-right font-mono">{pct:.1f}%</span>
                </div>''')
        tc_html = f'''
        <div class="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
          <h3 class="text-sm font-semibold text-slate-700 mb-1">🗂 主题集中度（Risk Parity）</h3>
          <p class="text-xs mb-2">{tc.get("verdict", "")}</p>
          <div>{"".join(bars)}</div>
        </div>'''
    else:
        tc_html = f'''
        <div class="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
          <h3 class="text-sm font-semibold text-slate-700 mb-1">🗂 主题集中度</h3>
          <p class="text-xs text-slate-500">跳过：{tc.get("reason", "")}</p>
        </div>'''

    # 2. 估值警告
    vs = snap.get("valuation_sanity", {})
    if vs.get("warn_count", 0) == 0:
        vs_html = '''
        <div class="bg-white rounded-xl shadow-sm border border-emerald-200 p-4">
          <h3 class="text-sm font-semibold text-emerald-700 mb-1">💰 估值合理性</h3>
          <p class="text-xs text-emerald-600">🟢 当日 ⭐⭐⭐ 推荐估值均在合理范围</p>
        </div>'''
    else:
        items = []
        for w in vs.get("warnings", []):
            flags = " / ".join(w.get("flags", []))
            items.append(f'<li class="text-xs"><span class="font-semibold">{w.get("name")}</span> ({w.get("code")}): <span class="text-rose-600">{flags}</span></li>')
        vs_html = f'''
        <div class="bg-white rounded-xl shadow-sm border border-amber-200 p-4">
          <h3 class="text-sm font-semibold text-amber-700 mb-1">💰 估值合理性</h3>
          <p class="text-xs mb-2">⚠️ {vs["warn_count"]} 只 ⭐⭐⭐ 推荐有估值警告</p>
          <ul class="space-y-1 list-disc list-inside">{"".join(items)}</ul>
        </div>'''

    # 3. 13F 一致性
    tf = snap.get("thirteen_f_consistency", {})
    if tf.get("status") == "ok" and tf.get("items"):
        items = []
        for it in tf["items"]:
            items.append(f'<li class="text-xs">{it["verdict"]} <span class="font-semibold">{it["name"]}</span> ({it["code"]})</li>')
        tf_html = f'''
        <div class="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
          <h3 class="text-sm font-semibold text-slate-700 mb-1">📋 13F 一致性</h3>
          <p class="text-xs mb-2">{tf.get("total", 0)} 只 ⭐⭐⭐ 推荐有 13F 信号，矛盾 {tf.get("warn_count", 0)} 只</p>
          <ul class="space-y-1 list-disc list-inside">{"".join(items)}</ul>
        </div>'''
    else:
        tf_html = '''
        <div class="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
          <h3 class="text-sm font-semibold text-slate-700 mb-1">📋 13F 一致性</h3>
          <p class="text-xs text-slate-500">跳过：当日推荐无 13F 信号匹配</p>
        </div>'''

    # 4. 相关性矩阵
    cr = snap.get("correlation", {})
    if cr.get("status") == "ok":
        pairs = cr.get("high_corr_pairs", [])
        items = [f'<li class="text-xs">{p.get("name_a")} ↔ {p.get("name_b")}: <span class="font-mono">r={p.get("r"):.2f}</span></li>' for p in pairs[:8]]
        body = "".join(items) if items else f'<p class="text-xs text-emerald-600">🟢 无相关 > {cr.get("threshold", 0.85)} 的"伪分散"对</p>'
        cr_html = f'''
        <div class="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
          <h3 class="text-sm font-semibold text-slate-700 mb-1">📐 相关性矩阵（Markowitz）</h3>
          <p class="text-xs mb-2">分析 {cr.get("n_tickers", 0)} 只 ⭐⭐⭐ · 阈值 r &gt; {cr.get("threshold", 0.85)}</p>
          {f'<ul class="space-y-1 list-disc list-inside">{body}</ul>' if items else body}
        </div>'''
    else:
        cr_html = f'''
        <div class="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
          <h3 class="text-sm font-semibold text-slate-700 mb-1">📐 相关性矩阵</h3>
          <p class="text-xs text-slate-500">跳过：{cr.get("reason", "")}</p>
        </div>'''

    return f'''
<!-- ============ 风险反证 · 买前审查 ============ -->
<section id="audit-panel" class="max-w-7xl mx-auto px-6 py-10 bg-gradient-to-br from-violet-50 to-fuchsia-50 rounded-2xl my-6">
  <div class="flex items-center justify-between mb-4">
    <div>
      <div class="flex items-center gap-3 mb-1">
        <span class="text-3xl">🛡</span>
        <h2 class="text-2xl font-bold text-slate-900">风险反证 · 买前审查</h2>
      </div>
      <p class="text-slate-700">用经典金融理论（Risk Parity / Markowitz / 13F / 估值）给推荐做反方检查，帮助你决定是否继续研究。</p>
    </div>
    <div class="text-right">
      <div class="inline-block px-4 py-2 rounded-lg bg-{overall_color}-100 text-{overall_color}-800 font-semibold text-sm">{overall_text}</div>
      <p class="text-xs text-slate-500 mt-1">快照：{snap.get("ts", "?")} · {snap.get("picks_today_count", 0)} 只 picks</p>
    </div>
  </div>

  <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
    {tc_html}
    {vs_html}
    {tf_html}
    {cr_html}
  </div>

  <p class="text-xs text-slate-500 mt-4">
    数据来源：<code>data/snapshots/audit/picks_audit_*.json</code> · 重新生成：
    <code class="bg-slate-200 px-2 py-0.5 rounded">python3 -m stock_research.jobs.audit_picks_v2</code>
  </p>
</section>
'''


def _fmt_market_cap(usd: float | None) -> str:
    """yfinance market_cap (USD float) → "$1.23T" / "$45.6B" / "$8.7M"."""
    if not usd or usd <= 0:
        return ""
    abs_u = float(usd)
    if abs_u >= 1e12:
        return f"${abs_u/1e12:.2f}T"
    if abs_u >= 1e9:
        return f"${abs_u/1e9:.1f}B"
    if abs_u >= 1e6:
        return f"${abs_u/1e6:.1f}M"
    return f"${abs_u:,.0f}"


def _pick_market_key(code: str | None, market: str | None) -> str | None:
    """Map a picks row to dashboard market buckets."""
    c = str(code or "").upper()
    m = str(market or "")
    mu = m.upper()
    if mu in {"US", "HK", "CN"}:
        return {"US": "us", "HK": "hk", "CN": "cn"}[mu]
    if c.endswith(".HK") or "港股" in m:
        return "hk"
    if (
        c.endswith((".SS", ".SZ", ".BJ"))
        or "A股" in m
        or "A 股" in m
        or (c.isdigit() and len(c) == 6)
    ):
        return "cn"
    if "美股" in m or (c and "." not in c and not c.isdigit()):
        return "us"
    return None


def _date_prefix(ts: str | None) -> str:
    """Return YYYY-MM-DD-ish prefix for comparing DB dates with JSON timestamps."""
    return str(ts or "")[:10]


def _parse_payload_ts(payload: dict | None):
    if not isinstance(payload, dict):
        return None
    for key in ("generated_at", "updated_at", "completed_at", "as_of", "date", "timestamp"):
        value = payload.get(key)
        if not value:
            continue
        try:
            return datetime.fromisoformat(str(value).replace("Z", "").split(".")[0])
        except Exception:
            continue
    return None


def _choose_fresher_payload(file_payload: dict, db_payload: dict) -> dict:
    """Prefer the fresher artifact; DB pipeline mirrors can lag latest files."""
    if not db_payload:
        return file_payload or {}
    if not file_payload:
        return db_payload or {}
    file_ts = _parse_payload_ts(file_payload)
    db_ts = _parse_payload_ts(db_payload)
    if file_ts and db_ts and file_ts > db_ts:
        return file_payload
    return db_payload


def _load_v2_watchlist_picks() -> tuple[list[dict], dict[str, dict]]:
    """自选股 · AI 优选：最新 run 的 recommendation_picks JOIN manual_watchlist。

    Returns (picks_list, watchlist_ratings)：
      - picks_list 喂前端 PICKS_JSON，结构匹配 _pickMarket / _ratingBadge / _pickPriceHtml 等消费者
      - watchlist_ratings 喂前端 WATCHLIST_RATINGS_JSON（自选股列表评级 badge）

    JOIN 用 symbol 直接对齐 —— manual_watchlist 的 market 字段是 "A股·沪交所/美股/US/HK"
    杂混历史值，跟 recommendation_picks 的 "US/CN/HK" 对不上；symbol 才是稳的 key。
    """
    db_path = _duckdb_path()
    if not os.path.exists(db_path):
        return [], {}
    try:
        import duckdb
    except ImportError:
        return [], {}

    market_label = {"US": "美股", "CN": "A股", "HK": "港股"}
    model_source_map = {"US": "v2_us", "CN": "v2_cn", "HK": "v2_hk"}
    # V2 评级 → V1 风格星标文本：前端 _ratingScore 看 "⭐⭐⭐/⭐⭐/⭐" 前缀派生 0-3 档，
    # 让现有 _ratingBadge / _pickReasons 逻辑直接复用，不动 JS。
    rating_label = {
        "strong_buy": "⭐⭐⭐ 高分研究",
        "buy":        "⭐⭐ 买前研究",
        "watch":      "⭐ 观察",
        "avoid":      "⛔ 不建议",
    }

    rows: list[tuple] = []
    try:
        con = duckdb.connect(db_path, read_only=True)
        try:
            tables = {str(r[0]) for r in con.execute("SHOW TABLES").fetchall()}
            if not {"recommendation_runs", "recommendation_picks", "manual_watchlist"}.issubset(tables):
                return [], {}
            rows = con.execute(
                """
                WITH latest AS (
                    SELECT run_id, run_date, generated_at
                    FROM recommendation_runs
                    ORDER BY generated_at DESC LIMIT 1
                )
                SELECT
                    p.symbol,
                    COALESCE(NULLIF(w.name, ''), p.name)        AS name,
                    p.market,
                    p.rating,
                    p.signal,
                    p.total_score,
                    p.factor_scores_json,
                    p.recommendation_reason,
                    p.risk_flags_json,
                    p.entry_price,
                    p.entry_currency,
                    l.run_date,
                    l.generated_at
                FROM manual_watchlist w
                JOIN recommendation_picks p ON p.symbol = w.symbol
                JOIN latest l               ON l.run_id = p.run_id
                ORDER BY p.total_score DESC NULLS LAST
                """
            ).fetchall()
        finally:
            con.close()
    except Exception as e:
        print(f"  ⚠️ 自选股 picks 加载失败 (V2 JOIN): {e}")
        return [], {}

    picks_list: list[dict] = []
    watchlist_ratings: dict[str, dict] = {}
    for (sym, name, market, rating, signal, total_score,
         factor_json, reason, risk_json, entry_price, entry_ccy,
         run_date, generated_at) in rows:
        try:
            factor_scores = json.loads(factor_json) if factor_json else {}
        except Exception:
            factor_scores = {}
        try:
            risk_flags = json.loads(risk_json) if risk_json else []
        except Exception:
            risk_flags = []
        rating_text = rating_label.get(rating, rating or "")
        # 红旗拼到 rating 后面：前端 _buildPickReasons 按 " · " 拆出来当 cons 显示。
        # risk_flags 元素是 dict {code, severity, message}，取 message 兜底 code。
        if risk_flags:
            flag_texts = []
            for f in risk_flags:
                if isinstance(f, dict):
                    msg = f.get("message") or f.get("code")
                    if msg:
                        flag_texts.append(str(msg))
                elif f:
                    flag_texts.append(str(f))
            if flag_texts:
                rating_text = f"{rating_text} · {'｜'.join(flag_texts)}"
        pick = {
            "code": sym,
            "name": name,
            "market": market_label.get(market, market),
            "rating": rating_text,
            "signal": signal,
            "total_score": float(total_score) if total_score is not None else None,
            "pick_date": run_date.isoformat() if run_date else None,
            "model_source": model_source_map.get(market, "v2"),
            "entry_price": float(entry_price) if entry_price is not None else None,
            "entry_currency": entry_ccy,
            "recommendation_reason": reason,
            "factor_scores": factor_scores,
            "risk_flags": risk_flags,
            "ai_at": generated_at.isoformat() if generated_at else None,
        }
        picks_list.append(pick)
        watchlist_ratings[sym] = {
            "rating": rating_text,
            "total_score": pick["total_score"],
        }
    return picks_list, watchlist_ratings


def _load_latest_pick_dates_by_market() -> dict[str, str | None]:
    """DB-first latest production pick_date per market.

    JSON artifacts may lag a market-specific pipeline. The dashboard should use
    DuckDB as the source of truth, and only borrow JSON timestamps when they are
    at least as fresh as the DB date.
    """
    out: dict[str, str | None] = {"us": None, "hk": None, "cn": None}
    db_path = _duckdb_path()
    if not os.path.exists(db_path):
        return out
    try:
        import duckdb
        con = duckdb.connect(db_path, read_only=True)
        tables = {str(r[0]) for r in con.execute("SHOW TABLES").fetchall()}
        if "recommendation_picks" in tables and "recommendation_runs" in tables:
            latest_run = con.execute(
                "SELECT run_id, generated_at FROM recommendation_runs ORDER BY generated_at DESC LIMIT 1"
            ).fetchone()
            if latest_run:
                rows = con.execute(
                    """
                    SELECT market, MAX(created_at) AS latest_date
                    FROM recommendation_picks
                    WHERE run_id = ?
                    GROUP BY market
                    """,
                    [latest_run[0]],
                ).fetchall()
                run_ts = str(latest_run[1]) if latest_run[1] is not None else None
                for market, latest_date in rows:
                    key = _pick_market_key(None, market)
                    if key:
                        out[key] = run_ts or (str(latest_date) if latest_date is not None else None)
            if "picks" not in tables:
                con.close()
                return out
        # 2026-05-21 V1 cutover：去 V1 picks 兜底，V2 path 上面已覆盖各市场最新日期
        con.close()
        rows = []
    except Exception as e:
        print(f"  ⚠️  从 DuckDB 读 picks 日期失败: {e}")
        return out

    for code, market, model_source, latest_date in rows:
        key = _pick_market_key(code, market)
        if not key or latest_date is None:
            continue
        d = str(latest_date)[:10]
        if out[key] is None or d > str(out[key])[:10]:
            out[key] = d
    return out


_LEGACY_FLAG_REPR_RE = re.compile(
    r"\{'code':\s*'[^']*',\s*'severity':\s*'[^']*',\s*'message':\s*'([^}]*?)'\}"
)


def _sanitize_legacy_flag_text(text: str) -> str:
    """旧版 enrich 把 V2 risk_flag dict 直接 str() 进文本;source_raw_snapshots
    是审计表不改写历史,读取端兜底把 repr 翻译回 message。"""
    if not text or "{'code':" not in text:
        return text
    return _LEGACY_FLAG_REPR_RE.sub(r"\1", text)


def _runtime_v2_enrichment_map(con, tables: set[str]) -> dict[str, dict]:
    """Latest v2 system-universe enrichment keyed by symbol and market:symbol."""
    if "source_raw_snapshots" not in tables:
        return {}
    try:
        rows = con.execute(
            """
            SELECT payload_json, fetched_at
            FROM source_raw_snapshots
            WHERE source = 'v2_system_enrichment'
            ORDER BY fetched_at DESC
            """
        ).fetchall()
    except Exception:
        return {}

    out: dict[str, dict] = {}
    for payload_json, fetched_at in rows:
        try:
            payload = json.loads(payload_json) if isinstance(payload_json, str) else payload_json
        except Exception:
            continue
        if not isinstance(payload, dict):
            continue
        symbol = str(payload.get("symbol") or "").strip().upper()
        raw_symbol = str(payload.get("raw_symbol") or "").strip().upper()
        market = str(payload.get("market") or "").strip().upper()
        if not symbol:
            continue
        fetched_ts = payload.get("fetched_at") or (
            fetched_at.isoformat(sep=" ", timespec="seconds") if hasattr(fetched_at, "isoformat") else fetched_at
        )
        row = {
            "earnings": payload.get("earnings") or "",
            "conclusion": payload.get("conclusion") or "",
            "risks": _sanitize_legacy_flag_text(payload.get("risks") or ""),
            "info_breakdown": payload.get("info_breakdown") or "",
            "notes": payload.get("notes") or "",
            "verification": payload.get("source_text") or "",
            "updated_at": fetched_ts,
            "earnings_fetched_at": fetched_ts,
            "_v2_enrichment_source": "source_raw_snapshots.v2_system_enrichment",
        }
        keys = {symbol}
        if raw_symbol:
            keys.add(raw_symbol)
        if market:
            keys.add(f"{market}:{symbol}")
            if raw_symbol:
                keys.add(f"{market}:{raw_symbol}")
        for key in keys:
            out.setdefault(key, row)
    return out


def _runtime_db_explorer_snapshot() -> dict:
    """构造 /api/db/all-stocks 的构建时快照。

    这个快照用于 HTML 离线展示，避免页面依赖本机 8765 API 才能看到
    "已拉取股票池"。它只读当前 DuckDB，不写库。
    """
    db_path = _duckdb_path()
    if not os.path.exists(db_path):
        return {}
    try:
        import duckdb
        con = duckdb.connect(db_path, read_only=True)
        tables = {str(r[0]) for r in con.execute("SHOW TABLES").fetchall()}
        if "system_universe" not in tables or "price_daily" not in tables:
            con.close()
            return {}

        def _jsonify(v):
            if v is None:
                return None
            if hasattr(v, "isoformat"):
                if hasattr(v, "hour"):
                    return v.isoformat(sep=" ", timespec="seconds")
                return v.isoformat()
            return v

        latest_prices = con.execute(
            """
            SELECT market, symbol, trade_date, close, prev_close, currency, market_cap,
                   forward_pe, trailing_pe, peg_ratio, ytd_pct, one_week_pct,
                   one_month_pct, one_year_pct, source, fetched_at
            FROM price_daily
            QUALIFY ROW_NUMBER() OVER (
                PARTITION BY market, symbol
                ORDER BY trade_date DESC, fetched_at DESC
            ) = 1
            """
        ).fetchall()
        price_cols = [d[0] for d in con.description]
        prices_by_code = {}
        for row in latest_prices:
            d = dict(zip(price_cols, row))
            prices_by_code[str(d.get("symbol") or "")] = d

        pick_rows = []
        latest_run = con.execute(
            "SELECT run_id, generated_at FROM recommendation_runs ORDER BY generated_at DESC LIMIT 1"
        ).fetchone()
        if latest_run:
            pick_rows = con.execute(
                """
                SELECT market, symbol, name, rating, signal, total_score,
                       factor_scores_json, recommendation_reason, risk_flags_json,
                       universe_scope, source_origin
                FROM recommendation_picks
                WHERE run_id = ?
                """,
                [latest_run[0]],
            ).fetchall()
        picks_by_code = {}
        for row in pick_rows:
            data = dict(zip(
                [
                    "market", "symbol", "name", "rating", "signal", "total_score",
                    "factor_scores_json", "recommendation_reason", "risk_flags_json",
                    "universe_scope", "source_origin",
                ],
                row,
            ))
            picks_by_code[str(data.get("symbol") or "")] = data

        enrichment_by_code = _runtime_v2_enrichment_map(con, tables)
        groups: dict[str, list[dict[str, Any]]] = {"美股": [], "A股": [], "港股": [], "其他": []}
        market_map = {"US": "美股", "HK": "港股", "CN": "A股"}
        rows = con.execute(
            "SELECT pool_id, market, symbol, raw_symbol, name, theme, industry, source FROM system_universe WHERE active = TRUE"
        ).fetchall()
        con.close()
        for pool_id, market, symbol, raw_symbol, name, theme, industry, source in rows:
            market_label = market_map.get(str(market or "").upper(), str(market or ""))
            if market_label not in groups:
                market_label = "其他"
            code = str(symbol or "").strip()
            meta = {
                "code": code,
                "name": _display_stock_name(market, name) or code,
                "name_en": name or "",
                "market": market_label,
                "industry": industry or "",
                "theme": theme or "",
                "ai_relevance": "科技/AI universe",
                "source": f"pool:{pool_id or 'system_tech_universe'}",
                "_source_origin": "system_pool",
                "earnings_fetched_at": None,
            }
            enrich_row = (
                enrichment_by_code.get(f"{str(market or '').upper()}:{code}")
                or enrichment_by_code.get(code)
                or enrichment_by_code.get(str(raw_symbol or "").strip().upper())
                or {}
            )
            if enrich_row:
                meta.update(enrich_row)
            price_row = prices_by_code.get(code) or prices_by_code.get(str(raw_symbol or "").strip()) or {}
            merged = {k: _jsonify(v) for k, v in meta.items()}
            for k, v in price_row.items():
                if k in ("market", "symbol", "name"):
                    continue
                merged[f"price_{k}"] = _jsonify(v)
            # V1 dashboard JS 兼容别名：把 V2 列名映射到 V1 字段
            if "price_trade_date" in merged:
                merged["price_date"] = merged["price_trade_date"]
            if "price_close" in merged:
                merged["price_price"] = merged["price_close"]
            pick_row = picks_by_code.get(code) or picks_by_code.get(str(raw_symbol or "").strip()) or {}
            for k, v in pick_row.items():
                if k in ("market", "symbol", "name"):
                    continue
                merged[f"pick_{k}"] = _jsonify(v)
            # V2 picks 兼容：把 factor_scores_json 拆出 val/trend/cred 子分 + 补 pick_date alias
            fs_json = pick_row.get("factor_scores_json") if pick_row else None
            if fs_json:
                try:
                    fs = json.loads(fs_json) if isinstance(fs_json, str) else fs_json
                    merged["pick_val_score"] = fs.get("valuation")
                    merged["pick_trend_score"] = fs.get("momentum")
                    merged["pick_cred_score"] = fs.get("data_quality")
                    merged["pick_coverage_score"] = fs.get("coverage")
                    merged["pick_ai_score"] = fs.get("ai_relevance")
                except Exception:
                    pass
            if pick_row.get("recommendation_reason") and not merged.get("conclusion"):
                merged["conclusion"] = pick_row.get("recommendation_reason")
            if pick_row.get("risk_flags_json") and not merged.get("risks"):
                try:
                    flags = json.loads(pick_row.get("risk_flags_json"))
                    # V2 flag 是 {code,severity,message} 结构,message 已是中文句子;
                    # 不允许 dict 直接进 f-string 变成 repr 文本。
                    texts = [
                        str(f.get("message") or f.get("text") or f.get("flag") or f.get("code") or "")
                        if isinstance(f, dict) else str(f)
                        for f in (flags or [])
                    ]
                    texts = [t for t in texts if t]
                    if texts:
                        merged["risks"] = "\n".join(f"- {t}" for t in texts)
                except Exception:
                    pass
            if latest_run:
                merged["pick_pick_date"] = _jsonify(latest_run[1])
            groups[market_label].append(merged)

        prices_date = None
        if prices_by_code:
            prices_date = max(str(v.get("trade_date") or "")[:10] for v in prices_by_code.values())
        picks_date = latest_run[1] if latest_run else None
        return {
            "as_of": {
                "prices_date": _jsonify(prices_date),
                "picks_date": _jsonify(picks_date),
            },
            "counts": {k: len(v) for k, v in groups.items()} | {"total": sum(len(v) for v in groups.values())},
            "groups": groups,
        }
    except Exception as e:
        print(f"  ⚠️  构建时 DB explorer 快照失败: {e}")
        return {}


def build():
    print("[1/3] 拉取数据 [DuckDB]...")
    clean_v2 = _is_clean_v2_db()
    db_stats = _runtime_db_stats()
    v2_stats = db_stats.get("v2") or {}
    if clean_v2:
        # V2 path：直接走 V2 表（system_universe + price_daily + recommendation_picks），
        # 不再调任何 V1 函数。chain/chain_tier 等 V1-only 主观字段为 None，前端做空值处理。
        from stock_db import fetch_research_records_v2
        records = fetch_research_records_v2()
        # 自选股 · AI 优选：manual_watchlist JOIN 最新 run 的 recommendation_picks
        # （前端 PICKS_JSON + WATCHLIST_RATINGS_JSON 共用同一份数据，避免两份不一致）
        picks, _watchlist_ratings_v2 = _load_v2_watchlist_picks()
        pool_total = int(v2_stats.get("system_universe") or 0)
        pool_membership = int(v2_stats.get("pool_membership") or 0)
        price_daily = int(v2_stats.get("price_daily") or 0)
        rec_runs = int(v2_stats.get("recommendation_runs") or 0)
        rec_picks = int(v2_stats.get("recommendation_picks") or 0)
        plan_n = int(v2_stats.get("portfolio_plans") or 0)
        coverage = v2_stats.get("price_coverage") or {}
        print(f"  v2 系统池      = {pool_total}（pool_membership={pool_membership}）")
        print(f"  v2 行情/推荐   = price_daily={price_daily} · recommendation_runs={rec_runs} · recommendation_picks={rec_picks} · portfolio_plans={plan_n}")
        print(
            f"  v2 行情覆盖    = {coverage.get('priced', 0)}/{coverage.get('active_pool', 0)} "
            f"({coverage.get('pct', 0)}%)"
        )
        print(f"  records (V2) = {len(records)} 条（个股研究 / 产业链地图 用）")
    else:
        # V2 cutover 后 clean_v2 永远为 True；此分支理论上不进。
        # 留个 graceful 兜底，避免老 DB 启动炸：返回空集让 dashboard 仍能渲染骨架。
        print("  ⚠️  非 clean v2 DB — 系统已切到纯 V2 路径，records 留空")
        records, picks = [], []
        _watchlist_ratings_v2 = {}
    # 兼容旧 schema: market_cap 字段(人工填写"$2.8T")现在格式化自 yf_market_cap
    for r in records:
        r["market_cap"] = _fmt_market_cap(r.get("yf_market_cap"))

    # 各市场 AI 计算时间 — DB picks 是事实源；JSON 仅在同日时补时分秒，不允许把
    # dashboard 日期拉回比 DB 更旧（防 A 股 JSON 滞后污染早盘看板）。
    picks_timestamps = _load_latest_pick_dates_by_market()
    for key, fname in (("us", "data/latest/plan_a_v5.json"),
                       ("hk", "data/latest/hk_picks.json"),
                       ("cn", "data/a_share_picks.json")):
        fpath = os.path.join(_REPO, fname)
        if os.path.exists(fpath):
            try:
                with open(fpath, encoding="utf-8") as f:
                    file_ts = json.load(f).get("generated_at")
                db_ts = picks_timestamps.get(key)
                if file_ts and db_ts and _date_prefix(file_ts) == _date_prefix(db_ts):
                    picks_timestamps[key] = file_ts
            except Exception:
                pass
    print(f"  picks 各市场计算时间: {picks_timestamps}")

    # 读取模拟结果（如果存在）
    sim_file = os.path.join(_REPO, "simulation_plan_a.json")
    simulation = {}
    if os.path.exists(sim_file):
        with open(sim_file, encoding="utf-8") as f:
            simulation = json.load(f)
        print(f"  共 {len(simulation.get('stock_stats', {}))} 条模拟数据")

    # 读取专业分析数据 —— 双源：本地 JSON 文件 + DuckDB pipeline 镜像
    def _load_json(name):
        p = os.path.join(_REPO, name)
        if os.path.exists(p):
            with open(p, encoding="utf-8") as f:
                return json.load(f)
        return {}

    def _load_pipeline_db(name_no_ext):
        """从 DuckDB snapshots 表读 category='pipeline' 最新快照。"""
        db_path = _duckdb_path()
        if not os.path.exists(db_path):
            return {}
        try:
            import duckdb
        except ImportError:
            return {}
        try:
            con = duckdb.connect(db_path, read_only=True)
            row = con.execute(
                "SELECT payload FROM snapshots WHERE category='pipeline' AND name=? "
                "ORDER BY taken_at DESC LIMIT 1",
                [name_no_ext],
            ).fetchone()
            con.close()
            if not row:
                return {}
            payload = row[0]
            return json.loads(payload) if isinstance(payload, str) else payload
        except Exception as e:
            print(f"  ⚠️  从 DuckDB 读 {name_no_ext} 失败: {e}")
            return {}

    # 文件源
    risk_metrics = _load_json("data/latest/risk_metrics.json")
    track_13f = _load_json("data/latest/track_13f.json")
    optimization = _load_json("data/latest/optimization_result.json")
    plan_a_v6 = _load_json("data/latest/plan_a_v5.json")
    history_data = _load_json("data/latest/history_data.json")
    # 今日推荐展示必须覆盖最新 V2 批次的完整候选，而不是只展示综合 Top 20。
    # discovery_candidates.json 只作为富字段补充；候选范围以 DuckDB recommendation_picks 为准。
    discovery_json = _load_json("data/discovery_candidates.json")
    data_usability_audit = _load_json("data/latest/recommendation_data_usability_audit.json")
    source_health = _load_json("data/latest/source_health.json")
    _augment_source_health_with_catalyst(source_health)
    _augment_source_health_with_paid_sources(source_health)
    batch_meta_main = _runtime_v2_latest_batch_meta()
    if (
        data_usability_audit
        and batch_meta_main.get("batch_run_id")
        and data_usability_audit.get("run_id") != batch_meta_main.get("batch_run_id")
    ):
        print(
            "  ⚠️ 数据可用性审计跳过："
            f"audit run {data_usability_audit.get('run_id')} != latest {batch_meta_main.get('batch_run_id')}"
        )
        data_usability_audit = {}
    v2_candidates_main = _runtime_v2_recommendations()
    if v2_candidates_main:
        rich_by_ticker = {
            str(c.get("ticker") or c.get("code") or "").upper(): c
            for c in (discovery_json.get("candidates") or [])
            if isinstance(c, dict)
        }
        catalyst_by_ticker = _build_catalyst_index()
        current_strategy_version = batch_meta_main.get("strategy_version")
        appearance_idx = _build_appearance_index(current_strategy_version)
        appearance_total_runs = (appearance_idx.get("_meta") or {}).get("total_runs", 0)
        merged_candidates = []
        for c in v2_candidates_main:
            rich = rich_by_ticker.get(str(c.get("ticker") or c.get("code") or "").upper()) or {}
            item = dict(c)
            for k in ("sector", "location", "pead"):
                if rich.get(k) is not None:
                    item[k] = rich.get(k)
            if rich.get("detail"):
                item["detail"] = {
                    **(item.get("detail") or {}),
                    **(rich.get("detail") or {}),
                    "recommendation_reason": item.get("recommendation_reason") or (item.get("detail") or {}).get("recommendation_reason"),
                    "risk_flags": item.get("risk_flags") or (item.get("detail") or {}).get("risk_flags"),
                    "factor_scores": item.get("factor_scores") or (item.get("detail") or {}).get("factor_scores") or (rich.get("detail") or {}).get("factor_scores"),
                }
            if rich.get("etfs"):
                item["etfs"] = rich.get("etfs")
            tk_upper = str(item.get("ticker") or item.get("code") or "").upper()
            cat = catalyst_by_ticker.get(tk_upper)
            if cat:
                item["catalyst"] = cat
            ap = appearance_idx.get(tk_upper)
            if ap:
                item["appearance_count"] = ap.get("count")
                item["consecutive_runs"] = ap.get("consecutive")
                item["first_seen_date"] = ap.get("first_seen_date")
                item["first_seen_run_id"] = ap.get("first_seen_run_id")
                item["rank_up"] = ap.get("rank_up")
                item["score_up"] = ap.get("score_up")
                item["prev_rank"] = ap.get("prev_rank")
                item["prev_score"] = ap.get("prev_score")
            qtag = _signal_quality_tag_for_pick(
                tk_upper,
                item.get("composite_z") if item.get("composite_z") is not None else item.get("total_score"),
                (history_data or {}).get("tickers") or {},
            )
            if qtag:
                item["quality_tag"] = qtag
            merged_candidates.append(item)
        v2_stats_main = _runtime_db_stats().get("v2") or {}
        dropouts = _build_dropouts(current_strategy_version)
        # Dump 给 morning_brief 复用（避免 morning_brief 自己连 DuckDB 锁冲突）。
        # 2026-05-28 事故：refresh_system_universe_v2.py 持 DuckDB 写锁时，
        # appearance_idx 拿不到数据，dump 会把好的 picks_appearance.json 覆盖成空,
        # 导致今日决策台「📰 今日推荐动向」回退到「total_runs<2 冷启动」兜底文案。
        # 修：tickers 空 + total_runs 0 + dropouts 空，三者全空就不覆盖，保留旧 JSON。
        appearance_tickers = {k: v for k, v in appearance_idx.items() if not k.startswith("_")}
        try:
            appearance_dump_path = os.path.join(_REPO, "data", "latest", "picks_appearance.json")
            if not appearance_tickers and not dropouts and not appearance_total_runs:
                print("  ⚠️ picks_appearance dump 跳过（DB 锁或冷启动，appearance_idx 空，保留旧 JSON 避免误覆盖）")
            else:
                with open(appearance_dump_path, "w", encoding="utf-8") as _f:
                    json.dump({
                        "generated_at": datetime.now().isoformat(),
                        "total_runs": appearance_total_runs,
                        "tickers": appearance_tickers,
                        "dropouts": dropouts,
                    }, _f, ensure_ascii=False, default=str)
        except Exception as _e:
            print(f"  ⚠️ picks_appearance.json dump 失败（不阻断 dashboard）：{_e}")
        discovery = {
            **discovery_json,
            "generated_at": batch_meta_main.get("batch_generated_at") or discovery_json.get("generated_at") or datetime.now().isoformat(timespec="seconds"),
            "source": "v2:recommendation_picks",
            "universe_scope": "system_tech_universe",
            "universe_size": v2_stats_main.get("system_universe") or len(merged_candidates),
            "candidates": merged_candidates,
            "appearance_total_runs": appearance_total_runs,
            "dropouts": dropouts,
            "history_strategy_version": current_strategy_version,
            "data_usability_audit": data_usability_audit,
        }
    else:
        discovery = discovery_json
        if clean_v2 and discovery and not discovery.get("source"):
            discovery = {**discovery, "source": "v2:discovery_candidates"}
        if discovery and data_usability_audit:
            discovery = {**discovery, "data_usability_audit": data_usability_audit}
    if discovery and batch_meta_main:
        discovery = {
            **discovery,
            **batch_meta_main,
            "display_count": len(discovery.get("candidates") or []),
        }

    # DuckDB 源
    risk_metrics_db = _load_pipeline_db("risk_metrics")
    track_13f_db = _load_pipeline_db("track_13f")
    optimization_db = _load_pipeline_db("optimization_result")
    plan_a_v6_db = _load_pipeline_db("plan_a_v5")
    history_data_db = _load_pipeline_db("history_data")
    plan_a_v6_runtime = _choose_fresher_payload(plan_a_v6, plan_a_v6_db)
    db_explorer_snapshot = _runtime_db_explorer_snapshot()

    if risk_metrics:
        print(f"  风险指标已加载 (Sharpe={risk_metrics.get('sharpe', 'N/A')})")
    if track_13f:
        print(f"  13F 数据已加载 ({len(track_13f.get('tickers', {}))} 只美股)")
    if optimization:
        print(f"  优化结果已加载 ({len(optimization.get('current_plan', []))} 只)")
    if plan_a_v6:
        print(f"  方案 A v6 已加载 ({len(plan_a_v6.get('plan_v5', []))} 只 · Sharpe {plan_a_v6.get('portfolio_metrics', {}).get('annual_sharpe', 'N/A')})")
    if history_data:
        print(f"  历史数据已加载 ({len(history_data.get('tickers', {}))} 只 × 2 年日K)")
    if discovery:
        print(f"  AI 推荐已加载 [{discovery.get('source') or 'legacy'}] ({len(discovery.get('candidates', []))} 只 · universe {discovery.get('universe_size', 0)})")
    elif clean_v2:
        print("  AI 推荐已加载 [none] (clean v2，等待 v2 推荐生成)")
    if source_health:
        degraded = [
            k for k, v in (source_health.get("sources") or {}).items()
            if (v or {}).get("status") not in (None, "", "ok", "healthy")
        ]
        if degraded:
            print(f"  数据源降级提示: {', '.join(degraded)}")
    print(f"  [DuckDB 镜像] risk={'✓' if risk_metrics_db else '✗'} 13f={'✓' if track_13f_db else '✗'} "
          f"opt={'✓' if optimization_db else '✗'} plan={'✓' if plan_a_v6_db else '✗'} "
          f"hist={'✓' if history_data_db else '✗'}")

    us_count = sum(1 for r in records if "美股" in (r["market"] or ""))
    cn_count = len(records) - us_count
    high_ai = sum(1 for r in records if "极强" in (r["ai_relevance"] or "") or "强（直接受益）" == (r["ai_relevance"] or ""))

    print("[2/3] 渲染 HTML...")
    html = HTML_TEMPLATE
    html = html.replace("{UPDATE_TIME}", datetime.now().strftime("%Y-%m-%d %H:%M"))
    html = html.replace("{TODAY_DATE}", datetime.now().strftime("%Y-%m-%d"))
    junior_radar = _runtime_load_json("data/latest/junior_stock_radar.json") or {
        "generated_at": None, "ipo_calendar": {}, "unlock_radar": [], "junior_pool": [], "summary_week": {},
    }
    html = html.replace("{JUNIOR_RADAR_JSON}", json.dumps(junior_radar, ensure_ascii=False, default=str))
    fx_payload = fx_rates.get_fx_payload()
    html = html.replace("{FX_RATES_JSON}", json.dumps(fx_payload.get("rates") or fx_rates.FALLBACK_FX_TO_RMB, ensure_ascii=False))
    html = html.replace("{FX_RATES_AS_OF}", str(fx_payload.get("as_of") or "fallback"))
    html = html.replace("{HEADLINE}", MY_VIEW["headline"])
    html = html.replace("{SUMMARY}", MY_VIEW["summary"])
    html = html.replace("{TOTAL}", str(len(records)))
    html = html.replace("{HIGH_AI}", str(high_ai))
    html = html.replace("{US_COUNT}", str(us_count))
    html = html.replace("{CN_COUNT}", str(cn_count))

    html = html.replace("{THESIS_CARDS}", "\n".join(thesis_card_html(t) for t in MY_VIEW["thesis"]))
    html = html.replace("{HUNDRED_X_CARDS}", "\n".join(hundred_x_card_html(c) for c in HUNDRED_X_CONDITIONS))
    html = html.replace("{TIMELINE_ITEMS}", "\n".join(timeline_item_html(t) for t in EVOLUTION))

    scarce_with_ticker_html = []
    for s in SCARCE_THEMES:
        s_copy = dict(s)
        s_copy["tickers"] = " ".join(f'<span class="ticker-badge">{t}</span>' for t in s["tickers"])
        scarce_with_ticker_html.append(s_copy)
    html = html.replace("{SCARCE_THEME_CARDS}", "\n".join(scarce_theme_card_html(t) for t in scarce_with_ticker_html))

    _key_events = _load_key_events_for_dashboard()
    print(f"  关键事件 (L3 行业大会): {len(_key_events)} 条 · 主源 data/latest/key_events.json")
    html = html.replace("{EVENT_CARDS}", "\n".join(event_card_html(e) for e in _key_events))

    theme_sections = "\n".join(theme_section_html(t, records) for t in THEMES)
    html = html.replace("{THEME_SECTIONS}", theme_sections)

    # 反向审查面板（picks_audit 快照）— 2026-05-11 起单源走 DuckDB
    audit_snap_db = load_audit_snapshot_from_db()
    panel_db_inner = (
        audit_panel_html(audit_snap_db) if audit_snap_db else
        '<section class="max-w-7xl mx-auto px-6 py-10 bg-rose-50 rounded-2xl my-6">'
        '<p class="text-rose-700">⚠️ DuckDB <code>snapshots</code> 表中暂无 picks_audit 数据，待 daily_refresh 跑完累积。</p>'
        '</section>'
    )
    ts_db = (audit_snap_db or {}).get("ts", "—")[:16] if audit_snap_db else "—"

    audit_panel_combined = f'''
<div id="audit-panel">
  <div class="max-w-7xl mx-auto px-6 pt-6">
    <div class="text-xs text-slate-500 mb-1">数据源：<span class="font-mono px-1.5 py-0.5 bg-emerald-50 text-emerald-800 rounded">DuckDB · {ts_db}</span></div>
  </div>
  <div id="audit-panel-db-wrap" data-source="duckdb" data-ts="{ts_db}">{panel_db_inner}</div>
</div>
'''
    html = html.replace("{AUDIT_PANEL}", audit_panel_combined)
    html = html.replace("{SOURCE_HEALTH_PANEL}", source_health_panel_html(source_health))
    html = html.replace("{TODAY_DECISION_PANEL}", today_decision_panel_html())
    html = html.replace("{RUNTIME_STATUS_PANEL}", runtime_status_panel_html())
    html = html.replace("{STRATEGY_MARKET_ADVISORY}", strategy_market_advisory_html())
    html = html.replace("{ALLOCATION_FRAMEWORK_CARD}", allocation_framework_card_html())
    html = html.replace("{HOLDINGS_SELL_ALERT}", holdings_sell_alert_html())
    html = html.replace("{AI_NAV_DISCOVERY}", ai_workbench_nav_html(1))
    html = html.replace("{AI_NAV_BACKTEST}", ai_workbench_nav_html(2))
    html = html.replace("{AI_NAV_PORTFOLIO}", ai_workbench_nav_html(3))
    html = html.replace("{TRUST_VERDICT_PANEL}", trust_verdict_panel_html())
    html = html.replace("{US_VALIDATION_PROGRESS}", us_validation_progress_html())
    html = html.replace("{P0_POLICY_VALIDATION_PANEL}", p0_policy_validation_panel_html())
    html = html.replace("{RECOMMENDATION_READINESS_PANEL}", recommendation_readiness_panel_html(compact=True))
    html = html.replace("{US_STRICT_TRIAL_SECTION}", us_strict_trial_section_html())
    early_growth_radar = _runtime_load_json("data/latest/early_growth_radar.json") or {}
    html = html.replace("{EARLY_GROWTH_RADAR_SECTION}", early_growth_radar_section_html(early_growth_radar))

    if audit_snap_db:
        n_picks_db = audit_snap_db.get("picks_today_count", 0)
        print(f"  反向审查快照已加载 [DuckDB]（{n_picks_db} 只 picks @ {ts_db}）")

    # Stock Pill 链条上下文：V2 chain_metadata 表优先（rule_classify + manual_override），
    # data/stock_chain_overrides.json 仅做未入库前的本地兜底
    # ALSO: manual_watchlist 的 name / industry / business 也合并进来 —— 这样用户在
    # 「我的持仓 → 编辑」里填的行业 / 主营业务,F5 刷新页面也能看到（不依赖热刷新）
    chain_info: dict = {}
    try:
        import duckdb as _duckdb
        _chain_conn = _duckdb.connect(os.path.join(_REPO, "stock_history_v2.duckdb"), read_only=True)
        _chain_tables = {str(r[0]) for r in _chain_conn.execute("SHOW TABLES").fetchall()}
        if "chain_metadata" in _chain_tables:
            for market, symbol, chain, tier, role, intro, source in _chain_conn.execute("""
                SELECT market, symbol, chain, chain_tier, chain_role, layman_intro, source
                FROM chain_metadata
            """).fetchall():
                # 即使 chain 为 NULL 也保留(用户可能只填了 tier='N/A')
                chain_info[symbol] = {
                    "chain": chain,
                    "chain_tier": tier,
                    "chain_role": role,
                    "layman_intro": intro,
                    "source": source,
                }
            print(f"  Stock Pill 链条上下文已加载 [chain_metadata]({len(chain_info)} 条)")
        if "manual_watchlist" in _chain_tables:
            # 合并 manual_watchlist 的 name / industry / business
            _mw_cols = {r[0] for r in _chain_conn.execute("DESCRIBE manual_watchlist").fetchall()}
            ind_sel = "industry" if "industry" in _mw_cols else "NULL"
            bus_sel = "business" if "business" in _mw_cols else "NULL"
            for symbol, name, industry, business in _chain_conn.execute(
                f"SELECT symbol, name, {ind_sel}, {bus_sel} FROM manual_watchlist"
            ).fetchall():
                if symbol not in chain_info:
                    chain_info[symbol] = {}
                if name:     chain_info[symbol]["name"]     = name
                if industry: chain_info[symbol]["industry"] = industry
                if business: chain_info[symbol]["business"] = business
            print(f"  Stock Pill 链条上下文已合并 [manual_watchlist name/industry/business]")
        _chain_conn.close()
    except Exception as e:
        print(f"  ⚠️ 链条上下文 DB 加载失败，回退 overrides.json: {e}")
    if not chain_info:
        overrides_path = os.path.join(_REPO, "data", "stock_chain_overrides.json")
        if os.path.exists(overrides_path):
            try:
                with open(overrides_path, encoding="utf-8") as f:
                    overrides = json.load(f)
                for code, meta in overrides.items():
                    if code.startswith("_"):
                        continue
                    chain_info[code] = meta
                print(f"  Stock Pill 链条上下文已加载 [overrides 兜底]({len(chain_info)} 条)")
            except Exception as e:
                print(f"  ⚠️ 链条上下文 overrides 加载失败: {e}")
    html = html.replace("{WATCHLIST_CHAIN_INFO_JSON}", json.dumps(chain_info, ensure_ascii=False))

    # V2: V1 discovery_history/discovery_tracking 表已删；
    # AI 推荐历史从 recommendation_picks + pick_outcomes 注入前端。
    disc_hist_strategy = (discovery or {}).get("history_strategy_version") or (discovery or {}).get("strategy_version")
    disc_hist = _runtime_v2_discovery_history(strategy_version=disc_hist_strategy)
    # enrich: 给每条历史推荐补 quality_tag — 用「当时往前 60d」的价格窗口（PIT 回溯）。
    # 用 r.run_date 作为 as_of，避免显示"现在看这只票是追涨"而误导成"当时是追涨"。
    sys.path.insert(0, _REPO)
    from stock_research.core.quality_tag import classify_from_history as _qt_classify
    _hist_tickers = (history_data or {}).get("tickers") or {}
    for _h in disc_hist:
        _tk = str(_h.get("ticker") or _h.get("code") or "").upper()
        _tag = _qt_classify(_tk, _h.get("score"), _hist_tickers,
                            mode="score_0_100", as_of_date=_h.get("run_date"))
        if _tag:
            _h["quality_tag"] = _tag.as_dict()
    strategy_suffix = f" · strategy={disc_hist_strategy}" if disc_hist_strategy else ""
    print(f"  AI 推荐历史已加载 [V2 pick_outcomes] ({len(disc_hist)} 条{strategy_suffix})")
    html = html.replace("{DISCOVERY_HISTORY_JSON}", json.dumps(disc_hist, ensure_ascii=False, default=str))

    # 2026-05-26: V2 路径自选股 AI 评级 — 跟 PICKS_JSON 同源（_load_v2_watchlist_picks
    # 一次 JOIN 同时算出 picks 和 ratings dict，避免两边漂移）
    watchlist_ratings = _watchlist_ratings_v2
    print(f"  自选股 AI 评级注入: {len(watchlist_ratings)} 只命中最新 run")
    html = html.replace("{WATCHLIST_RATINGS_JSON}", json.dumps(watchlist_ratings, ensure_ascii=False))

    # 2026-05-25: 自选股 coverage 注入 — 让前端"未评级" badge 区分四种原因
    #   in_picks (前端 WATCHLIST_RATINGS 命中) / in_universe / dropped_from_universe / not_in_universe
    # 见 _wlRatingBadge 分支说明
    watchlist_coverage: dict[str, str] = {}
    try:
        _cov_conn = duckdb.connect(os.path.join(_REPO, "stock_history_v2.duckdb"), read_only=True)
        try:
            uni_active = {r[0] for r in _cov_conn.execute(
                "SELECT symbol FROM system_universe WHERE active = TRUE"
            ).fetchall()}
            uni_dropped = {r[0] for r in _cov_conn.execute(
                "SELECT symbol FROM system_universe WHERE active = FALSE"
            ).fetchall()}
            for (sym,) in _cov_conn.execute("SELECT symbol FROM manual_watchlist").fetchall():
                if sym in uni_active:
                    watchlist_coverage[sym] = "in_universe"
                elif sym in uni_dropped:
                    watchlist_coverage[sym] = "dropped_from_universe"
                else:
                    watchlist_coverage[sym] = "not_in_universe"
        finally:
            _cov_conn.close()
        n_in = sum(1 for v in watchlist_coverage.values() if v == "in_universe")
        n_drop = sum(1 for v in watchlist_coverage.values() if v == "dropped_from_universe")
        n_out = sum(1 for v in watchlist_coverage.values() if v == "not_in_universe")
        print(f"  自选股 coverage: {n_in} 现役科技池 / {n_drop} 已下池 / {n_out} universe 不覆盖")
    except Exception as e:
        print(f"  ⚠️ watchlist_coverage 加载失败: {e}")
    html = html.replace("{WATCHLIST_COVERAGE_JSON}", json.dumps(watchlist_coverage, ensure_ascii=False))
    html = html.replace("{RECORDS_JSON}", json.dumps(records, ensure_ascii=False, default=str))
    html = html.replace("{PICKS_JSON}", json.dumps(picks, ensure_ascii=False, default=str))
    html = html.replace("{PICKS_TIMESTAMPS_JSON}", json.dumps(picks_timestamps, ensure_ascii=False))
    html = html.replace("{SIMULATION_JSON}", json.dumps(simulation, ensure_ascii=False))
    html = html.replace("{RISK_METRICS_JSON_DB}", json.dumps(risk_metrics_db, ensure_ascii=False))
    html = html.replace("{TRACK_13F_JSON_DB}", json.dumps(track_13f_db, ensure_ascii=False))
    html = html.replace("{OPTIMIZATION_JSON_DB}", json.dumps(optimization_db, ensure_ascii=False))
    html = html.replace("{PLAN_A_V6_JSON_DB}", json.dumps(plan_a_v6_runtime, ensure_ascii=False))
    html = html.replace("{DISCOVERY_JSON}", json.dumps(discovery, ensure_ascii=False))
    html = html.replace("{DB_EXPLORER_JSON}", json.dumps(db_explorer_snapshot, ensure_ascii=False))

    review_embed_path = os.path.join(_REPO, "data", "latest", "real_holding_review.json")
    review_embed = {}
    if os.path.exists(review_embed_path):
        try:
            with open(review_embed_path, encoding="utf-8") as f:
                review_embed = json.load(f)
            n = len(review_embed.get("items") or [])
            heat_n = sum(
                1 for i in (review_embed.get("items") or [])
                if (i.get("industry_heat") or {}).get("industry_heat_badge")
            )
            print(f"  真实持仓体检嵌入看板: {n} 只 · 板块热度 {heat_n} 只")
        except Exception as e:
            print(f"  ⚠️  real_holding_review.json 读取失败: {e}")
    else:
        try:
            sys.path.insert(0, os.path.join(_REPO, "scripts", "lib"))
            import stock_db as _sdb
            review_embed = _sdb.fetch_latest_real_holding_review() or {}
            if review_embed:
                print(f"  真实持仓体检嵌入看板: 来自 DuckDB ({len(review_embed.get('items') or [])} 只)")
        except Exception as e:
            print(f"  ⚠️  真实持仓体检嵌入跳过: {e}")
    html = html.replace("{REAL_HOLDING_REVIEW_JSON}", json.dumps(review_embed, ensure_ascii=False, default=str))

    # Catalyst signal validation embed (data/latest/catalyst_validation.json)
    catalyst_validation_path = os.path.join(_REPO, "data", "latest", "catalyst_validation.json")
    catalyst_validation_data = {}
    if os.path.exists(catalyst_validation_path):
        try:
            with open(catalyst_validation_path, encoding="utf-8") as _f:
                catalyst_validation_data = json.load(_f)
            n_types = len((catalyst_validation_data or {}).get("summary_by_type") or {})
            print(f"  催化信号验证嵌入: {n_types} 个事件类型")
        except Exception as e:
            print(f"  ⚠️ catalyst_validation 加载失败: {e}")
    html = html.replace("{CATALYST_VALIDATION_JSON}", json.dumps(catalyst_validation_data, ensure_ascii=False, default=str))

    # 证据不足 gate (2026-06-01): 喂「今天 AI 推荐的组合」顶部"仅研究观察"横幅。
    # 只读已算好的 evidence(grade + 成熟样本数),前端据此渲染,不在前端重算。
    recommendation_evidence_embed = _runtime_load_json("data/latest/recommendation_evidence.json") or {}
    _ev_grade = (recommendation_evidence_embed or {}).get("evidence_grade", "—")
    _ev_mature = ((recommendation_evidence_embed or {}).get("review_coverage") or {}).get("v2_total_mature", 0)
    print(f"  证据 gate 嵌入: grade={_ev_grade} · 成熟样本={_ev_mature}")
    html = html.replace("{RECOMMENDATION_EVIDENCE_JSON}", json.dumps(recommendation_evidence_embed, ensure_ascii=False, default=str))

    # AI 配仓 — Static (A 类: buy-and-hold from inception) — DuckDB 优先，fallback JSON
    plan_for_bt = plan_a_v6_runtime or plan_a_v6
    history_for_bt = history_data_db or history_data
    backtest_db = compute_plan_forward_track(plan_for_bt, history_for_bt)
    if backtest_db and backtest_db.get("metrics"):
        m = backtest_db["metrics"]
        inception = backtest_db.get("inception_date") or "?"
        baseline = backtest_db.get("baseline_date") or "?"
        print(f"  AI 配仓 A 静态: 锁定 {inception} → 基线 {baseline} · 跟踪 {m['n_tracked_days']} 日"
              f" · 累计 {m['cumulative_return_pct']}% (vs SPY {m['bench_cumulative_return_pct']}%)")
    # 透传 candidate_universe 到前端 _BACKTEST,用于顶部溯源条 (2026-05-27)
    if backtest_db is not None and isinstance(plan_for_bt, dict):
        backtest_db["candidate_universe"] = plan_for_bt.get("candidate_universe")
    html = html.replace("{PLAN_BACKTEST_JSON_DB}", json.dumps(backtest_db, ensure_ascii=False))

    # AI 配仓 — Dynamic (C 类: weekly Monday rebalance, P1+P2)
    dynamic_db = compute_dynamic_rebalance_track(history_for_bt)
    if dynamic_db and dynamic_db.get("metrics"):
        m = dynamic_db["metrics"]
        print(f"  AI 配仓 C 动态: {m['n_rebalances']} 次调仓 · 累计手续费 {dynamic_db.get('total_commission_pct', 0)}% · "
              f"跟踪 {m['n_tracked_days']} 日 · 累计 {m['cumulative_return_pct']}% (vs SPY {m['bench_cumulative_return_pct']}%)")
    html = html.replace("{PLAN_DYNAMIC_JSON_DB}", json.dumps(dynamic_db, ensure_ascii=False))

    # 📡 AI 主题雷达 — 行业理解层（非推荐池）· 见 docs/V2/AI主题雷达_产品定位.md
    # 只读 chain_metadata + recommendation_picks + manual_watchlist（仅打 "已在自选" 标记，不写）。
    ai_radar_html = ""
    try:
        from stock_research.core.ai_radar import (
            build_ai_radar_payload,
            build_theme_evidence_panel,
            build_etf_consensus_panel,
            build_freshness_panel,
            build_research_shortlist,
            render_ai_radar_section,
        )
        _radar_conn = duckdb.connect(_duckdb_path(), read_only=True)
        try:
            radar_payload = build_ai_radar_payload(_radar_conn)
            theme_panel = build_theme_evidence_panel(_radar_conn)
            etf_panel = build_etf_consensus_panel(_radar_conn)
            freshness_panel = build_freshness_panel(_radar_conn)
            shortlist = build_research_shortlist(_radar_conn, top_n=5)
        finally:
            _radar_conn.close()
        production_panel = _runtime_load_json("data/latest/production_acceptance_check.json")
        quality_panel = _runtime_load_json("data/latest/recommendation_quality_gate.json")
        ai_radar_html = render_ai_radar_section(
            radar_payload,
            my_view_headline=MY_VIEW["headline"],
            my_view_summary=MY_VIEW["summary"],
            theme_panel=theme_panel,
            etf_panel=etf_panel,
            freshness_panel=freshness_panel,
            shortlist=shortlist,
            production_panel=production_panel,
            quality_panel=quality_panel,
        )
        n_chains = len(radar_payload.get("chains") or [])
        n_picks = radar_payload.get("n_picks_total") or 0
        n_covered = radar_payload.get("n_picks_with_chain") or 0
        n_uncov = (radar_payload.get("coverage_audit") or {}).get("n_uncovered") or 0
        n_themes = len((theme_panel or {}).get("themes") or [])
        n_src_ok = sum(t.get("sources_ok", 0) for t in (theme_panel or {}).get("themes") or [])
        n_src_tot = sum(t.get("sources_total", 0) for t in (theme_panel or {}).get("themes") or [])
        n_etfs = len((etf_panel or {}).get("etfs") or [])
        n_etf_uni = (etf_panel or {}).get("summary", {}).get("n_holdings_in_universe", 0)
        n_etf_tot = (etf_panel or {}).get("summary", {}).get("n_holdings_total", 0)
        print(f"  AI 主题雷达: {n_chains} 条链 · picks {n_covered}/{n_picks} 已分类 · 覆盖率审计 {n_uncov} 只 · "
              f"主题证据卡 {n_themes} 张 · 数据源 {n_src_ok}/{n_src_tot} ok · "
              f"ETF 共识 {n_etfs} 个 · universe 命中 {n_etf_uni}/{n_etf_tot}")
    except Exception as _e:
        print(f"  ⚠️ AI 主题雷达渲染失败（不阻断 dashboard）：{_e}")
        ai_radar_html = (
            '<section id="ai-radar" class="max-w-7xl mx-auto px-6 py-10" style="display:none">'
            '<div class="bg-amber-50 ring-1 ring-amber-200 rounded p-4 text-sm text-amber-800">'
            'AI 主题雷达数据加载失败，请稍后重试或查看后台日志。</div></section>'
        )
    html = html.replace("{AI_RADAR_SECTION}", ai_radar_html)

    # 2026-06-01 评审 #2: 完整性 sanity check + 原子写入
    # 各处 fetch 有 try/except 吞掉锁错误返回空数据，build() 不抛但生成的 HTML 残缺。
    # 健康 HTML 通常 ≥ 4MB（含完整 records + picks JSON），降级 HTML 约 1-2MB。
    # 用文件大小做最便宜的 sanity check：太小则 raise 让 _build_with_retry 重试 + 保留旧 HTML。
    MIN_HEALTHY_HTML_BYTES = 3_000_000
    n_records = len(records) if records else 0
    if len(html) < MIN_HEALTHY_HTML_BYTES or n_records < 50:
        raise RuntimeError(
            f"dashboard 生成的 HTML 不完整（{len(html)} bytes / records={n_records}）— "
            f"可能因 DuckDB 锁导致各路径降级。abort 保留旧 HTML 等待 retry。"
        )

    tmp_path = OUTPUT + ".tmp"
    with open(tmp_path, "w", encoding="utf-8") as f:
        f.write(html)
    os.replace(tmp_path, OUTPUT)
    print(f"[3/3] 已生成：{OUTPUT}（{len(html)} bytes, {n_records} records）")
    print(f"\n用浏览器打开：file://{OUTPUT}")


def _build_with_retry(max_attempts: int = 3, retry_delay_s: float = 5.0) -> int:
    """主入口：跑 build()，失败时重试 (DuckDB 锁缓解)。

    2026-06-01 评审 #2: dashboard 构建经常因 DuckDB 写锁失败导致覆盖旧 HTML。
    现在策略:
      1. fetch_research_records_v2 等读路径已改 force_read_only=True
      2. build() 失败时重试 3 次 × 5s 间隔
      3. 全部失败时退出码 1，旧 HTML 保留 (build 内部已改原子写入)
    """
    import time
    last_err = None
    for attempt in range(1, max_attempts + 1):
        try:
            build()
            return 0
        except Exception as e:
            last_err = e
            msg = str(e)
            is_lock = ("Conflicting lock" in msg or "different configuration" in msg
                       or "Could not set lock" in msg)
            # HTML 不完整也算可重试（吞锁错误后生成的降级版本）
            is_incomplete = "HTML 不完整" in msg
            if attempt < max_attempts and (is_lock or is_incomplete):
                print(f"\n⚠️ dashboard build attempt {attempt}/{max_attempts} 失败 ({'HTML 不完整' if is_incomplete else 'DuckDB 锁'})，{retry_delay_s}s 后重试...")
                print(f"   {msg[:200]}")
                time.sleep(retry_delay_s)
            else:
                # 非锁错误立刻退出；锁错误用完重试次数退出
                raise
    print(f"❌ dashboard build 3 次重试后仍失败: {last_err}", file=sys.stderr)
    return 1


if __name__ == "__main__":
    sys.exit(_build_with_retry())
